#[allow(dead_code)]
fn build_metadata_command_reference_index(
    rows: &[ConfigRow],
) -> BTreeMap<String, MetadataCommandReference> {
    let metadata_texts = build_metadata_text_rows(rows);
    build_metadata_command_reference_index_from_texts(&metadata_texts)
}

fn build_metadata_command_reference_index_from_texts(
    rows: &[MetadataTextRow],
) -> BTreeMap<String, MetadataCommandReference> {
    let mut index = BTreeMap::new();
    for row in rows {
        let (Some(kind), Some(header)) = (row.kind.as_deref(), row.header.as_ref()) else {
            continue;
        };
        index.insert(
            row.file_name.clone(),
            MetadataCommandReference {
                kind: kind.to_string(),
                name: header.name.clone(),
            },
        );
    }
    index
}

#[allow(dead_code)]
fn build_metadata_object_reference_index(rows: &[ConfigRow]) -> BTreeMap<String, String> {
    let metadata_texts = build_metadata_text_rows(rows);
    build_metadata_object_reference_index_from_texts(&metadata_texts)
}

fn build_metadata_object_reference_index_from_texts(
    rows: &[MetadataTextRow],
) -> BTreeMap<String, String> {
    let mut index = BTreeMap::new();
    let empty_form_refs = BTreeMap::new();
    let empty_template_refs = BTreeMap::new();
    let subsystem_refs = build_subsystem_source_reference_index_from_texts(rows);
    for row in rows {
        if let Some(name) = parse_configuration_reference_text(&row.text) {
            index.insert(row.file_name.clone(), format!("Configuration.{name}"));
            continue;
        }
        let (Some(kind), Some(header)) = (row.kind.as_deref(), row.header.as_ref()) else {
            continue;
        };
        let reference = if kind == "Subsystem" {
            subsystem_refs
                .get(&header.uuid)
                .and_then(subsystem_source_reference_name)
                .unwrap_or_else(|| format!("{kind}.{}", header.name))
        } else {
            format!("{kind}.{}", header.name)
        };
        index.insert(row.file_name.clone(), reference);
        if kind == "Enum" {
            for value in parse_enum_values_from_text(&row.text) {
                index.insert(
                    value.uuid,
                    format!("Enum.{}.EnumValue.{}", header.name, value.name),
                );
            }
        }
        for command in nested_command_headers_from_text(&row.text, &row.file_name) {
            index.insert(
                command.uuid,
                format!("{}.{}.Command.{}", kind, header.name, command.name),
            );
        }
        for (child, marker_start) in
            nested_headers_with_offsets_from_text(&row.text, &row.file_name, |_| true)
        {
            if let Some(reference) = standalone_child_reference(
                kind,
                &header.name,
                &header.uuid,
                &row.text,
                marker_start,
                &child,
                &empty_form_refs,
                &empty_template_refs,
            ) {
                index.entry(child.uuid).or_insert(reference);
            }
        }
        if kind == "WebService" {
            for operation in
                nested_web_service_operation_headers_from_text(&row.text, &row.file_name)
            {
                index.insert(
                    operation.uuid,
                    format!("WebService.{}.Operation.{}", header.name, operation.name),
                );
            }
        }
        if kind == "HTTPService" {
            insert_http_service_child_role_refs(&mut index, &row.text, &header.uuid, &header.name);
        }
    }
    index
}

fn build_role_rights_object_reference_index(
    object_refs: &BTreeMap<String, String>,
    form_refs: &BTreeMap<String, FormSourceReference>,
) -> BTreeMap<String, String> {
    let mut refs = object_refs.clone();
    for (uuid, form_ref) in form_refs {
        if let Some(reference) = form_source_reference_name(form_ref) {
            refs.insert(uuid.clone(), reference);
        }
    }
    refs
}

fn build_metadata_order_index_from_texts(rows: &[MetadataTextRow]) -> BTreeMap<String, usize> {
    let mut index = BTreeMap::new();
    for row in rows {
        let Some(header_uuid) = parse_configuration_header_uuid(&row.text) else {
            continue;
        };
        for (order, child) in
            parse_configuration_child_objects(&row.text, &row.file_name, &header_uuid)
                .into_iter()
                .enumerate()
        {
            index.entry(child.header.uuid).or_insert(order);
        }
    }
    index
}

fn parse_configuration_header_uuid(text: &str) -> Option<String> {
    if !text.trim_start().starts_with("{2,") {
        return None;
    }
    let marker = "{1,0,";
    let marker_start = text.find(marker)?;
    let header_uuid_start = marker_start + marker.len();
    let header_uuid_end = header_uuid_start + 36;
    let header_uuid = text.get(header_uuid_start..header_uuid_end)?;
    if !is_uuid_text(header_uuid) || !is_metadata_header_marker(text, header_uuid_end) {
        return None;
    }
    Some(header_uuid.to_string())
}

fn insert_http_service_child_role_refs(
    index: &mut BTreeMap<String, String>,
    text: &str,
    owner_uuid: &str,
    owner_name: &str,
) {
    for template in parse_http_service_url_templates_from_text(text, owner_uuid) {
        let template_ref = format!(
            "HTTPService.{owner_name}.URLTemplate.{}",
            template.header.name
        );
        index.insert(template.header.uuid.clone(), template_ref.clone());
        for method in template.methods {
            index.insert(
                method.header.uuid,
                format!("{template_ref}.Method.{}", method.header.name),
            );
        }
    }
}

fn build_standalone_content_references(
    rows: &[MetadataTextRow],
    object_refs: &BTreeMap<String, String>,
    form_refs: &BTreeMap<String, FormSourceReference>,
    template_refs: &BTreeMap<String, TemplateSourceReference>,
    subsystem_refs: &BTreeMap<String, SubsystemSourceReference>,
) -> StandaloneContentReferences {
    let mut standalone_object_refs = object_refs.clone();
    for (uuid, form_ref) in form_refs {
        if let Some(reference) = form_source_reference_name(form_ref) {
            standalone_object_refs.insert(uuid.clone(), reference);
        }
    }
    for (uuid, template_ref) in template_refs {
        if let Some(reference) = template_source_reference_name(template_ref) {
            standalone_object_refs.insert(uuid.clone(), reference);
        }
    }
    for (uuid, subsystem_ref) in subsystem_refs {
        if let Some(reference) = subsystem_source_reference_name(subsystem_ref) {
            standalone_object_refs.insert(uuid.clone(), reference);
        }
    }

    for row in rows {
        let (Some(kind), Some(header)) = (row.kind.as_deref(), row.header.as_ref()) else {
            continue;
        };
        let mut seen = BTreeSet::new();
        for (child, marker_start) in
            nested_headers_with_offsets_from_text(&row.text, &row.file_name, |_| true)
        {
            if let Some(reference) = standalone_child_reference(
                kind,
                &header.name,
                &header.uuid,
                &row.text,
                marker_start,
                &child,
                form_refs,
                template_refs,
            ) && seen.insert(child.uuid.clone())
            {
                standalone_object_refs.insert(child.uuid, reference);
            }
        }
        for uuid in uuid_like_values(&row.text) {
            if standalone_object_refs.contains_key(&uuid) {
                continue;
            }
            if let Some(reference) = form_refs.get(&uuid).and_then(form_source_reference_name) {
                standalone_object_refs.insert(uuid, reference);
            } else if let Some(reference) = template_refs
                .get(&uuid)
                .and_then(template_source_reference_name)
            {
                standalone_object_refs.insert(uuid, reference);
            }
        }
    }

    StandaloneContentReferences {
        object_refs: standalone_object_refs,
    }
}

fn build_standalone_object_reference_index_from_texts(
    rows: &[MetadataTextRow],
    required_refs: &BTreeSet<String>,
    form_refs: &BTreeMap<String, FormSourceReference>,
    template_refs: &BTreeMap<String, TemplateSourceReference>,
    subsystem_refs: &BTreeMap<String, SubsystemSourceReference>,
) -> BTreeMap<String, String> {
    let mut index = BTreeMap::new();
    if required_refs.is_empty() {
        return index;
    }

    for row in rows {
        if required_refs.contains(&row.file_name) {
            if let Some(name) = parse_configuration_reference_text(&row.text) {
                index.insert(row.file_name.clone(), format!("Configuration.{name}"));
                continue;
            }
            let (Some(kind), Some(header)) = (row.kind.as_deref(), row.header.as_ref()) else {
                continue;
            };
            let reference = if kind == "Subsystem" {
                subsystem_refs
                    .get(&header.uuid)
                    .and_then(subsystem_source_reference_name)
                    .unwrap_or_else(|| format!("{kind}.{}", header.name))
            } else {
                format!("{kind}.{}", header.name)
            };
            index.insert(row.file_name.clone(), reference);
        }

        let (Some(kind), Some(header)) = (row.kind.as_deref(), row.header.as_ref()) else {
            continue;
        };
        if kind == "Enum" {
            for value in parse_enum_values_from_text(&row.text) {
                if required_refs.contains(&value.uuid) {
                    index.insert(
                        value.uuid,
                        format!("Enum.{}.EnumValue.{}", header.name, value.name),
                    );
                }
            }
        }
        if kind == "HTTPService" {
            insert_required_http_service_child_role_refs(
                &mut index,
                &row.text,
                &header.uuid,
                &header.name,
                required_refs,
            );
        }
        for (child, marker_start) in
            nested_headers_with_offsets_matching_uuids(&row.text, &row.file_name, required_refs)
        {
            if index.contains_key(&child.uuid) {
                continue;
            }
            if let Some(reference) = standalone_child_reference(
                kind,
                &header.name,
                &header.uuid,
                &row.text,
                marker_start,
                &child,
                form_refs,
                template_refs,
            ) {
                index.insert(child.uuid, reference);
            }
        }
    }

    index
}

fn insert_required_http_service_child_role_refs(
    index: &mut BTreeMap<String, String>,
    text: &str,
    owner_uuid: &str,
    owner_name: &str,
    required_refs: &BTreeSet<String>,
) {
    for template in parse_http_service_url_templates_from_text(text, owner_uuid) {
        let template_ref = format!(
            "HTTPService.{owner_name}.URLTemplate.{}",
            template.header.name
        );
        if required_refs.contains(&template.header.uuid) {
            index.insert(template.header.uuid.clone(), template_ref.clone());
        }
        for method in template.methods {
            if required_refs.contains(&method.header.uuid) {
                index.insert(
                    method.header.uuid,
                    format!("{template_ref}.Method.{}", method.header.name),
                );
            }
        }
    }
}

fn build_standalone_content_references_for_uuids(
    rows: &[MetadataTextRow],
    required_refs: &BTreeSet<String>,
    object_refs: &BTreeMap<String, String>,
    form_refs: &BTreeMap<String, FormSourceReference>,
    template_refs: &BTreeMap<String, TemplateSourceReference>,
    subsystem_refs: &BTreeMap<String, SubsystemSourceReference>,
) -> StandaloneContentReferences {
    let mut standalone_object_refs = object_refs.clone();
    for uuid in required_refs {
        if standalone_object_refs.contains_key(uuid) {
            continue;
        }
        if let Some(reference) = form_refs.get(uuid).and_then(form_source_reference_name) {
            standalone_object_refs.insert(uuid.clone(), reference);
        } else if let Some(reference) = template_refs
            .get(uuid)
            .and_then(template_source_reference_name)
        {
            standalone_object_refs.insert(uuid.clone(), reference);
        } else if let Some(reference) = subsystem_refs
            .get(uuid)
            .and_then(subsystem_source_reference_name)
        {
            standalone_object_refs.insert(uuid.clone(), reference);
        }
    }

    for row in rows {
        let (Some(kind), Some(header)) = (row.kind.as_deref(), row.header.as_ref()) else {
            continue;
        };
        for (child, marker_start) in
            nested_headers_with_offsets_matching_uuids(&row.text, &row.file_name, required_refs)
        {
            if standalone_object_refs.contains_key(&child.uuid) {
                continue;
            }
            if let Some(reference) = standalone_child_reference(
                kind,
                &header.name,
                &header.uuid,
                &row.text,
                marker_start,
                &child,
                form_refs,
                template_refs,
            ) {
                standalone_object_refs.insert(child.uuid, reference);
            }
        }
    }

    StandaloneContentReferences {
        object_refs: standalone_object_refs,
    }
}

fn build_help_reference_index(
    object_refs: &BTreeMap<String, String>,
    form_refs: &BTreeMap<String, FormSourceReference>,
    template_refs: &BTreeMap<String, TemplateSourceReference>,
    subsystem_refs: &BTreeMap<String, SubsystemSourceReference>,
) -> BTreeMap<String, String> {
    let mut refs = object_refs.clone();
    for (uuid, form_ref) in form_refs {
        if let Some(reference) = form_source_reference_name(form_ref) {
            refs.insert(uuid.clone(), reference);
        }
    }
    for (uuid, template_ref) in template_refs {
        if let Some(reference) = template_source_reference_name(template_ref) {
            refs.insert(uuid.clone(), reference);
        }
    }
    for (uuid, subsystem_ref) in subsystem_refs {
        if let Some(reference) = subsystem_source_reference_name(subsystem_ref) {
            refs.insert(uuid.clone(), reference);
        }
    }
    refs
}

fn build_functional_option_reference_index_from_texts(
    rows: &[MetadataTextRow],
    object_refs: &BTreeMap<String, String>,
    form_refs: &BTreeMap<String, FormSourceReference>,
    template_refs: &BTreeMap<String, TemplateSourceReference>,
    subsystem_refs: &BTreeMap<String, SubsystemSourceReference>,
) -> BTreeMap<String, String> {
    let mut refs = object_refs.clone();
    for (uuid, subsystem_ref) in subsystem_refs {
        if let Some(reference) = subsystem_source_reference_name(subsystem_ref) {
            refs.insert(uuid.clone(), reference);
        }
    }
    let required_refs = functional_option_reference_uuids_from_texts(rows);
    if required_refs.is_empty() {
        return refs;
    }
    for row in rows {
        let (Some(kind), Some(header)) = (row.kind.as_deref(), row.header.as_ref()) else {
            continue;
        };
        let mut seen = BTreeSet::new();
        for (child, marker_start) in
            nested_headers_with_offsets_matching_uuids(&row.text, &row.file_name, &required_refs)
        {
            if refs.contains_key(&child.uuid) || seen.contains(&child.uuid) {
                continue;
            }
            if let Some(reference) = standalone_child_reference(
                kind,
                &header.name,
                &header.uuid,
                &row.text,
                marker_start,
                &child,
                form_refs,
                template_refs,
            ) {
                seen.insert(child.uuid.clone());
                refs.insert(child.uuid, reference);
            }
        }
    }
    refs
}

fn functional_option_reference_uuids_from_texts(rows: &[MetadataTextRow]) -> BTreeSet<String> {
    let mut refs = BTreeSet::new();
    for row in rows {
        if row.kind.as_deref() != Some("FunctionalOption") {
            continue;
        }
        let Some(fields) = metadata_object_fields(&row.text) else {
            continue;
        };
        if let Some(uuid) = fields
            .get(2)
            .and_then(|field| parse_non_zero_uuid(field.trim()))
        {
            refs.insert(uuid);
        }
        if let Some(content) = fields.get(3) {
            refs.extend(uuid_like_values_in_text_order(content));
        }
    }
    refs
}

fn nested_headers_with_offsets_matching_uuids(
    text: &str,
    owner_uuid: &str,
    uuids: &BTreeSet<String>,
) -> Vec<(MetadataHeader, usize)> {
    let mut headers = Vec::new();
    let mut seen = BTreeSet::new();
    let mut offset = 0usize;
    let marker = "{1,0,";

    while let Some(relative) = text[offset..].find(marker) {
        let marker_start = offset + relative;
        let uuid_start = marker_start + marker.len();
        let uuid_end = uuid_start + 36;
        offset = uuid_start;

        let Some(uuid) = text.get(uuid_start..uuid_end) else {
            continue;
        };
        if uuid == owner_uuid
            || !uuids.contains(uuid)
            || !is_uuid_text(uuid)
            || !is_metadata_header_marker(text, uuid_end)
            || !seen.insert(uuid.to_string())
        {
            continue;
        }
        if let Some(header) = parse_metadata_header_from_text(text, uuid) {
            headers.push((header, marker_start));
        }
    }

    headers
}

fn standalone_child_reference(
    owner_kind: &str,
    owner_name: &str,
    owner_uuid: &str,
    text: &str,
    marker_start: usize,
    child: &MetadataHeader,
    form_refs: &BTreeMap<String, FormSourceReference>,
    template_refs: &BTreeMap<String, TemplateSourceReference>,
) -> Option<String> {
    if let Some(reference) = form_refs
        .get(&child.uuid)
        .and_then(form_source_reference_name)
    {
        return Some(reference);
    }
    if let Some(reference) = template_refs
        .get(&child.uuid)
        .and_then(template_source_reference_name)
    {
        return Some(reference);
    }
    if is_offset_inside_metadata_object_code(text, marker_start, 9) {
        return Some(format!("{owner_kind}.{owner_name}.Command.{}", child.name));
    }
    if owner_kind == "WebService" && is_offset_inside_metadata_object_code(text, marker_start, 1) {
        return Some(format!("WebService.{owner_name}.Operation.{}", child.name));
    }
    if owner_kind == "IntegrationService"
        && is_offset_inside_metadata_object_code(text, marker_start, 1)
    {
        return Some(format!(
            "IntegrationService.{owner_name}.IntegrationServiceChannel.{}",
            child.name
        ));
    }
    if is_offset_inside_metadata_object_code(text, marker_start, 11) {
        if let Some(tabular_section) = enclosing_metadata_header_for_code(text, marker_start, 11)
            && tabular_section.uuid != child.uuid
        {
            return Some(format!(
                "{owner_kind}.{owner_name}.TabularSection.{}.Attribute.{}",
                tabular_section.name, child.name
            ));
        }
        return Some(format!(
            "{owner_kind}.{owner_name}.TabularSection.{}",
            child.name
        ));
    }
    if let Some(tabular_section) = enclosing_metadata_header_for_code(text, marker_start, 11)
        && tabular_section.uuid != child.uuid
    {
        return Some(format!(
            "{owner_kind}.{owner_name}.TabularSection.{}.Attribute.{}",
            tabular_section.name, child.name
        ));
    }
    if let Some(reference) = tabular_section_attribute_reference(
        owner_kind,
        owner_name,
        owner_uuid,
        text,
        marker_start,
        child,
    ) {
        return Some(reference);
    }
    if metadata_kind_uses_register_resources(owner_kind)
        && is_offset_inside_metadata_object_code(text, marker_start, 5)
        && is_offset_inside_register_resource_list(text, marker_start)
    {
        return Some(format!("{owner_kind}.{owner_name}.Resource.{}", child.name));
    }
    if owner_kind == "Task"
        && is_offset_inside_metadata_object_code(text, marker_start, 4)
        && is_offset_inside_metadata_object_code(text, marker_start, 27)
    {
        return Some(format!(
            "Task.{owner_name}.AddressingAttribute.{}",
            child.name
        ));
    }
    if owner_kind == "DataProcessor"
        && is_offset_inside_metadata_object_code(text, marker_start, 27)
        && is_offset_inside_tabular_section_attribute_list(text, marker_start)
        && let Some((tabular_section, tabular_end)) =
            preceding_metadata_header_for_code_with_bounds(text, marker_start, 11)
        && tabular_section.uuid != child.uuid
        && !contains_metadata_header_uuid_between(text, tabular_end, marker_start, owner_uuid)
        && !contains_metadata_header_name_between(text, tabular_end, marker_start, owner_name)
    {
        return Some(format!(
            "{owner_kind}.{owner_name}.TabularSection.{}.Attribute.{}",
            tabular_section.name, child.name
        ));
    }
    if owner_kind == "DataProcessor"
        && is_offset_inside_metadata_object_code(text, marker_start, 27)
    {
        return Some(format!(
            "{owner_kind}.{owner_name}.Attribute.{}",
            child.name
        ));
    }
    if metadata_kind_uses_code27_attributes(owner_kind)
        && is_offset_inside_metadata_object_code(text, marker_start, 27)
    {
        return Some(format!(
            "{owner_kind}.{owner_name}.Attribute.{}",
            child.name
        ));
    }
    if metadata_kind_uses_code4_attributes(owner_kind)
        && is_offset_inside_metadata_object_code(text, marker_start, 4)
        && is_offset_inside_metadata_object_code(text, marker_start, 27)
    {
        return Some(format!(
            "{owner_kind}.{owner_name}.Attribute.{}",
            child.name
        ));
    }
    if owner_kind == "BusinessProcess"
        && is_offset_inside_metadata_object_code(text, marker_start, 3)
        && is_offset_inside_metadata_object_code(text, marker_start, 27)
        && !is_offset_inside_metadata_object_code(text, marker_start, 8)
    {
        return Some(format!(
            "{owner_kind}.{owner_name}.Attribute.{}",
            child.name
        ));
    }
    if is_offset_inside_metadata_object_code(text, marker_start, 5) {
        return Some(format!(
            "{owner_kind}.{owner_name}.Attribute.{}",
            child.name
        ));
    }
    if is_offset_inside_metadata_object_code(text, marker_start, 6) {
        if let Some(tabular_section) = enclosing_metadata_header_for_code(text, marker_start, 11)
            && tabular_section.uuid != child.uuid
        {
            return Some(format!(
                "{owner_kind}.{owner_name}.TabularSection.{}.Attribute.{}",
                tabular_section.name, child.name
            ));
        }
        return Some(format!(
            "{owner_kind}.{owner_name}.Attribute.{}",
            child.name
        ));
    }
    if metadata_kind_uses_register_resources(owner_kind)
        && is_offset_inside_metadata_object_code(text, marker_start, 8)
        && is_offset_inside_register_dimension_list(text, marker_start)
    {
        return Some(format!(
            "{owner_kind}.{owner_name}.Dimension.{}",
            child.name
        ));
    }
    if is_offset_inside_metadata_object_code(text, marker_start, 8) {
        if let Some(tabular_section) = preceding_metadata_header_for_code(text, marker_start, 11) {
            return Some(format!(
                "{owner_kind}.{owner_name}.TabularSection.{}.Attribute.{}",
                tabular_section.name, child.name
            ));
        }
        return Some(format!("{owner_kind}.{owner_name}.Resource.{}", child.name));
    }
    if is_offset_inside_metadata_object_code(text, marker_start, 10) {
        return Some(format!(
            "{owner_kind}.{owner_name}.Dimension.{}",
            child.name
        ));
    }
    None
}

fn tabular_section_attribute_reference(
    owner_kind: &str,
    owner_name: &str,
    _owner_uuid: &str,
    text: &str,
    marker_start: usize,
    child: &MetadataHeader,
) -> Option<String> {
    if !is_offset_inside_tabular_section_attribute_list(text, marker_start) {
        return None;
    }
    let (tabular_section, tabular_end) =
        preceding_metadata_header_for_code_with_bounds(text, marker_start, 11)?;
    if tabular_section.uuid == child.uuid
        || contains_any_metadata_header_between(text, tabular_end, marker_start)
    {
        return None;
    }
    Some(format!(
        "{owner_kind}.{owner_name}.TabularSection.{}.Attribute.{}",
        tabular_section.name, child.name
    ))
}

fn metadata_kind_uses_register_resources(kind: &str) -> bool {
    matches!(
        kind,
        "AccumulationRegister"
            | "AccountingRegister"
            | "CalculationRegister"
            | "InformationRegister"
    )
}

fn metadata_kind_uses_code27_attributes(kind: &str) -> bool {
    matches!(kind, "Report" | "Task" | "ChartOfCharacteristicTypes")
}

fn metadata_kind_uses_code4_attributes(kind: &str) -> bool {
    kind == "ExchangePlan" || metadata_kind_uses_register_resources(kind)
}

fn is_offset_inside_register_resource_list(text: &str, offset: usize) -> bool {
    const REGISTER_RESOURCE_LIST_MARKER: &str = "{b64d9a41-1642-11d6-a3c7-0050bae0a776,";
    let Some(start) = text[..offset].rfind(REGISTER_RESOURCE_LIST_MARKER) else {
        return false;
    };
    scan_1c_braced_value(text, start)
        .map(|end| offset < end)
        .unwrap_or(false)
}

fn is_offset_inside_register_dimension_list(text: &str, offset: usize) -> bool {
    const REGISTER_DIMENSION_LIST_MARKER: &str = "{b64d9a43-1642-11d6-a3c7-0050bae0a776,";
    let Some(start) = text[..offset].rfind(REGISTER_DIMENSION_LIST_MARKER) else {
        return false;
    };
    scan_1c_braced_value(text, start)
        .map(|end| offset < end)
        .unwrap_or(false)
}

fn is_offset_inside_tabular_section_attribute_list(text: &str, offset: usize) -> bool {
    const TABULAR_SECTION_ATTRIBUTE_LIST_MARKER: &str = "{5d24a9d1-098e-11d6-b9b8-0050bae0a95d,";
    let Some(start) = text[..offset].rfind(TABULAR_SECTION_ATTRIBUTE_LIST_MARKER) else {
        return false;
    };
    scan_1c_braced_value(text, start)
        .map(|end| offset < end)
        .unwrap_or(false)
}

fn is_offset_inside_data_processor_legacy_attribute_list(text: &str, offset: usize) -> bool {
    const DATA_PROCESSOR_LEGACY_ATTRIBUTE_LIST_MARKER: &str =
        "{ec6bb5e5-b7a8-4d75-bec9-658107a699cf,";
    let Some(start) = text[..offset].rfind(DATA_PROCESSOR_LEGACY_ATTRIBUTE_LIST_MARKER) else {
        return false;
    };
    scan_1c_braced_value(text, start)
        .map(|end| offset < end)
        .unwrap_or(false)
}

fn template_source_reference_name(template_ref: &TemplateSourceReference) -> Option<String> {
    let parts = template_ref
        .relative_path
        .iter()
        .filter_map(|part| part.to_str())
        .collect::<Vec<_>>();
    if parts.len() == 2 && parts.first() == Some(&"CommonTemplates") {
        let template_name = Path::new(parts[1]).file_stem()?.to_str()?;
        return Some(format!("CommonTemplate.{template_name}"));
    }
    if parts.len() == 4 && parts.get(2) == Some(&"Templates") {
        let owner_kind = metadata_kind_for_source_folder(parts[0])?;
        let owner_name = parts[1];
        let template_name = Path::new(parts[3]).file_stem()?.to_str()?;
        return Some(format!(
            "{owner_kind}.{owner_name}.Template.{template_name}"
        ));
    }
    None
}

fn subsystem_source_reference_name(subsystem_ref: &SubsystemSourceReference) -> Option<String> {
    let mut names = Vec::new();
    for part in subsystem_ref
        .relative_path
        .iter()
        .filter_map(|part| part.to_str())
    {
        if part == "Subsystems" {
            continue;
        }
        let name = Path::new(part).file_stem()?.to_str()?;
        names.push(name.to_string());
    }
    let mut names = names.into_iter();
    let first = names.next()?;
    let mut reference = format!("Subsystem.{first}");
    for name in names {
        reference.push_str(".Subsystem.");
        reference.push_str(&name);
    }
    Some(reference)
}

#[allow(dead_code)]
fn build_metadata_field_reference_index(rows: &[ConfigRow]) -> BTreeMap<String, String> {
    let metadata_texts = build_metadata_text_rows(rows);
    build_metadata_field_reference_index_from_texts(&metadata_texts)
}

fn build_metadata_field_reference_index_from_texts(
    rows: &[MetadataTextRow],
) -> BTreeMap<String, String> {
    let mut index = BTreeMap::new();
    for row in rows {
        for header in nested_metadata_headers_from_text(&row.text, &row.file_name) {
            index.insert(header.uuid, header.name);
        }
    }
    index
}

#[allow(dead_code)]
fn build_form_source_reference_index(rows: &[ConfigRow]) -> BTreeMap<String, FormSourceReference> {
    let metadata_texts = build_metadata_text_rows(rows);
    build_form_source_reference_index_from_texts(&metadata_texts)
}

fn build_form_source_reference_index_from_texts(
    rows: &[MetadataTextRow],
) -> BTreeMap<String, FormSourceReference> {
    let mut forms = Vec::<MetadataHeader>::new();
    let mut owner_paths_by_ref = BTreeMap::<String, BTreeSet<PathBuf>>::new();

    for row in rows {
        if is_form_metadata_text(&row.text, &row.file_name) {
            if let Some(header) = row.header.as_ref() {
                forms.push(header.clone());
            }
            continue;
        }
        let (Some(kind), Some(folder), Some(header)) =
            (row.kind.as_deref(), row.folder, row.header.as_ref())
        else {
            continue;
        };
        if !metadata_kind_can_own_forms(kind) {
            continue;
        }
        let owner_path = PathBuf::from(folder).join(sanitize_source_path_segment(&header.name));
        let Some(references) = owned_form_uuid_values(&row.text) else {
            continue;
        };
        for reference in references {
            owner_paths_by_ref
                .entry(reference)
                .or_default()
                .insert(owner_path.clone());
        }
    }

    let mut index = BTreeMap::new();
    for form in forms {
        let owner_matches = owner_paths_by_ref.get(&form.uuid).map(BTreeSet::iter);
        let relative_path = if let Some(mut owner_paths) = owner_matches {
            let first = owner_paths.next();
            let second = owner_paths.next();
            if let (Some(owner_path), None) = (first, second) {
                owner_path
                    .join("Forms")
                    .join(sanitize_source_path_segment(&form.name))
                    .with_extension("xml")
            } else {
                PathBuf::from("CommonForms")
                    .join(sanitize_source_path_segment(&form.name))
                    .with_extension("xml")
            }
        } else {
            PathBuf::from("CommonForms")
                .join(sanitize_source_path_segment(&form.name))
                .with_extension("xml")
        };
        let kind = if relative_path.starts_with("CommonForms") {
            "CommonForm"
        } else {
            "Form"
        };
        index.insert(
            form.uuid,
            FormSourceReference {
                relative_path,
                kind,
            },
        );
    }

    index
}

// Platform-level 1C markers for owned form lists in metadata blobs. These are
// not configuration object UUIDs and must not be replaced with DB-specific IDs.
const FORM_LIST_MARKERS: &[&str] = &[
    "fdf816d2-1ead-11d5-b975-0050bae0a95d",
    "fb880e93-47d7-4127-9357-a20e69c17545",
    "13134204-f60b-11d5-a3c7-0050bae0a776",
    "87c509ab-3d38-4d67-b379-aca796298578",
    "b64d9a44-1642-11d6-a3c7-0050bae0a776",
    "d5b0e5ed-256d-401c-9c36-f630cafd8a62",
    "a3b368c0-29e2-11d6-a3c7-0050bae0a776",
    "eb2b78a8-40a6-4b7e-b1b3-6ca9966cbc94",
    "3f7a8120-b71a-4265-98bf-4d9bc09b7719",
    "b8533c0c-2342-4db3-91a2-c2b08cbf6b23",
    "ec81ad10-ca07-11d5-b9a5-0050bae0a95d",
    "33f2e54b-37ce-4a7a-a569-b648d7aa4634",
    "3f58cbfb-4172-4e54-be49-561a579bb38b",
];

fn owned_form_uuid_values(text: &str) -> Option<BTreeSet<String>> {
    owned_form_uuid_values_in_text_order(text).map(|values| values.into_iter().collect())
}

fn owned_form_uuid_values_in_text_order(text: &str) -> Option<Vec<String>> {
    let mut refs = Vec::new();
    let mut seen = BTreeSet::new();
    let mut found_marker = false;
    for marker in FORM_LIST_MARKERS {
        let mut offset = 0usize;
        while let Some(relative_index) = text[offset..].find(marker) {
            let marker_index = offset + relative_index;
            found_marker = true;
            offset = marker_index + marker.len();

            let Some(block_start) = text[..marker_index].rfind('{') else {
                continue;
            };
            let Some(block_end) = scan_1c_braced_value(text, block_start) else {
                continue;
            };
            let Some(fields) = split_1c_braced_fields(&text[block_start..block_end], 0) else {
                continue;
            };
            if fields.first().map(|field| field.trim()) != Some(*marker) {
                continue;
            }
            let Some(count) = fields
                .get(1)
                .and_then(|field| field.trim().parse::<usize>().ok())
            else {
                continue;
            };
            for field in fields.iter().skip(2).take(count) {
                let value = field.trim().trim_matches('"').to_ascii_lowercase();
                if is_uuid_like_ascii(value.as_bytes()) && seen.insert(value.clone()) {
                    refs.push(value);
                }
            }
        }
    }
    found_marker.then_some(refs)
}

#[allow(dead_code)]
fn build_template_source_reference_index(
    rows: &[ConfigRow],
) -> BTreeMap<String, TemplateSourceReference> {
    let metadata_texts = build_metadata_text_rows(rows);
    build_template_source_reference_index_from_texts(rows, &metadata_texts)
}

fn build_template_source_reference_index_from_texts(
    rows: &[ConfigRow],
    metadata_texts: &[MetadataTextRow],
) -> BTreeMap<String, TemplateSourceReference> {
    let rows_by_file_name = rows
        .iter()
        .map(|row| (row.file_name.as_str(), row))
        .collect::<BTreeMap<_, _>>();
    let mut templates = Vec::<MetadataHeader>::new();
    let mut owner_paths_by_ref = BTreeMap::<String, Vec<PathBuf>>::new();

    for row in metadata_texts {
        if is_template_metadata_text(&row.text, &row.file_name) {
            if let Some(header) = row.header.as_ref() {
                templates.push(header.clone());
            }
            continue;
        }
        let (Some(kind), Some(folder), Some(header)) =
            (row.kind.as_deref(), row.folder, row.header.as_ref())
        else {
            continue;
        };
        if !metadata_kind_can_own_templates(kind) {
            continue;
        }
        let owner_path = PathBuf::from(folder).join(sanitize_source_path_segment(&header.name));
        for reference in uuid_like_values(&row.text) {
            owner_paths_by_ref
                .entry(reference)
                .or_default()
                .push(owner_path.clone());
        }
    }

    let mut index = BTreeMap::new();
    for template in templates {
        let owner_matches = owner_paths_by_ref
            .get(&template.uuid)
            .map(Vec::as_slice)
            .unwrap_or(&[]);
        let relative_path = if let [owner_path] = owner_matches {
            owner_path
                .join("Templates")
                .join(sanitize_source_path_segment(&template.name))
                .with_extension("xml")
        } else {
            PathBuf::from("CommonTemplates")
                .join(sanitize_source_path_segment(&template.name))
                .with_extension("xml")
        };
        let kind = if relative_path.starts_with("CommonTemplates") {
            "CommonTemplate"
        } else {
            "Template"
        };
        let body_id = format!("{}.0", template.uuid);
        let template_type = template_template_type_from_metadata(&template)
            .or_else(|| {
                rows_by_file_name
                    .get(body_id.as_str())
                    .and_then(|row| decode_hex(&row.binary_hex).ok())
                    .and_then(|bytes| infer_template_type_from_body(&bytes))
            })
            .unwrap_or("BinaryData");
        index.insert(
            template.uuid,
            TemplateSourceReference {
                relative_path,
                kind,
                template_type,
            },
        );
    }

    index
}

#[allow(dead_code)]
fn build_subsystem_source_reference_index(
    rows: &[ConfigRow],
) -> BTreeMap<String, SubsystemSourceReference> {
    let metadata_texts = build_metadata_text_rows(rows);
    build_subsystem_source_reference_index_from_texts(&metadata_texts)
}

fn build_subsystem_source_reference_index_from_texts(
    rows: &[MetadataTextRow],
) -> BTreeMap<String, SubsystemSourceReference> {
    let mut subsystems = BTreeMap::<String, (MetadataHeader, String)>::new();

    for row in rows {
        let Some(kind) = row.kind.as_deref() else {
            continue;
        };
        if kind != "Subsystem" {
            continue;
        }
        let Some(header) = row.header.as_ref() else {
            continue;
        };
        subsystems.insert(header.uuid.clone(), (header.clone(), row.text.clone()));
    }

    let subsystem_uuids = subsystems.keys().cloned().collect::<BTreeSet<_>>();
    let mut owners_by_child = BTreeMap::<String, Vec<String>>::new();
    for (owner_uuid, (_, owner_text)) in &subsystems {
        for reference in uuid_like_values(owner_text) {
            if reference != *owner_uuid && subsystem_uuids.contains(&reference) {
                owners_by_child
                    .entry(reference)
                    .or_default()
                    .push(owner_uuid.clone());
            }
        }
    }
    let mut parent_by_child = BTreeMap::<String, String>::new();
    for (child_uuid, owners) in owners_by_child {
        if let [owner_uuid] = owners.as_slice() {
            parent_by_child.insert(child_uuid, owner_uuid.clone());
        }
    }

    let mut memo = BTreeMap::<String, PathBuf>::new();
    for uuid in subsystems.keys() {
        let mut visiting = BTreeSet::<String>::new();
        let _ = resolve_subsystem_source_path(
            uuid,
            &subsystems,
            &parent_by_child,
            &mut memo,
            &mut visiting,
        );
    }

    memo.into_iter()
        .map(|(uuid, relative_path)| (uuid, SubsystemSourceReference { relative_path }))
        .collect()
}

fn resolve_subsystem_source_path(
    uuid: &str,
    subsystems: &BTreeMap<String, (MetadataHeader, String)>,
    parent_by_child: &BTreeMap<String, String>,
    memo: &mut BTreeMap<String, PathBuf>,
    visiting: &mut BTreeSet<String>,
) -> Option<PathBuf> {
    if let Some(path) = memo.get(uuid) {
        return Some(path.clone());
    }
    if !visiting.insert(uuid.to_string()) {
        return None;
    }
    let (header, _) = subsystems.get(uuid)?;
    let name = sanitize_source_path_segment(&header.name);
    let relative_path = if let Some(parent_uuid) = parent_by_child.get(uuid) {
        resolve_subsystem_source_path(parent_uuid, subsystems, parent_by_child, memo, visiting)
            .map(|parent_path| {
                parent_path
                    .with_extension("")
                    .join("Subsystems")
                    .join(&name)
                    .with_extension("xml")
            })
            .unwrap_or_else(|| {
                PathBuf::from("Subsystems")
                    .join(&name)
                    .with_extension("xml")
            })
    } else {
        PathBuf::from("Subsystems")
            .join(&name)
            .with_extension("xml")
    };
    visiting.remove(uuid);
    memo.insert(uuid.to_string(), relative_path.clone());
    Some(relative_path)
}

fn uuid_like_values(text: &str) -> BTreeSet<String> {
    uuid_like_values_in_text_order(text).into_iter().collect()
}

fn uuid_like_values_in_text_order(text: &str) -> Vec<String> {
    let bytes = text.as_bytes();
    let mut values = Vec::new();
    let mut seen = BTreeSet::new();
    if bytes.len() < 36 {
        return values;
    }
    for start in 0..=bytes.len() - 36 {
        let value = &bytes[start..start + 36];
        if is_uuid_like_ascii(value) {
            let value = String::from_utf8_lossy(value).to_ascii_lowercase();
            if seen.insert(value.clone()) {
                values.push(value);
            }
        }
    }
    values
}

fn is_uuid_like_ascii(value: &[u8]) -> bool {
    if value.len() != 36 {
        return false;
    }
    for (index, byte) in value.iter().copied().enumerate() {
        if matches!(index, 8 | 13 | 18 | 23) {
            if byte != b'-' {
                return false;
            }
        } else if !byte.is_ascii_hexdigit() {
            return false;
        }
    }
    true
}

fn infer_template_type_from_body(bytes: &[u8]) -> Option<&'static str> {
    let inflated = inflate_raw_deflate(bytes).ok()?;
    if inflated.starts_with(b"MOXCEL") {
        return Some("SpreadsheetDocument");
    }
    let Ok(text) = std::str::from_utf8(&inflated) else {
        return Some("BinaryData");
    };
    let text = text.trim_start_matches('\u{feff}').trim_start();
    let xml_text = text
        .starts_with("<?xml")
        .then_some(text)
        .or_else(|| text.find("<?xml").map(|index| &text[index..]));
    if xml_text.is_some_and(|xml| xml.contains("data-composition-system/appearance-template")) {
        Some("DataCompositionAppearanceTemplate")
    } else if xml_text.is_some_and(|xml| xml.contains("data-composition-system/schema")) {
        Some("DataCompositionSchema")
    } else if xml_text.is_some_and(|xml| xml.contains("8.3/xcf/scheme")) {
        Some("GraphicalSchema")
    } else if text.starts_with("<!DOCTYPE")
        || text.starts_with("<html")
        || text.starts_with("<?xml") && text.contains("<html")
    {
        Some("HTMLDocument")
    } else {
        Some("TextDocument")
    }
}

fn template_template_type_from_metadata(header: &MetadataHeader) -> Option<&'static str> {
    template_type_from_code(header.template_type_code?)
}

fn template_type_from_code(code: u32) -> Option<&'static str> {
    match code {
        0 => Some("SpreadsheetDocument"),
        1 => Some("BinaryData"),
        3 => Some("HTMLDocument"),
        4 => Some("TextDocument"),
        6 => Some("DataCompositionSchema"),
        7 => Some("DataCompositionAppearanceTemplate"),
        9 => Some("AddIn"),
        _ => None,
    }
}

fn form_help_asset_paths(
    rows: &[ConfigRow],
    rows_by_file_name: &BTreeMap<&str, &ConfigRow>,
    form_refs: &BTreeMap<String, FormSourceReference>,
) -> BTreeMap<String, SourceAsset> {
    let file_names = rows
        .iter()
        .map(|row| row.file_name.as_str())
        .collect::<BTreeSet<_>>();
    let mut paths = BTreeMap::new();
    for (form_uuid, form_ref) in form_refs {
        let row_prefix = format!("{form_uuid}.");
        let mut form_dir = form_ref.relative_path.clone();
        form_dir.set_extension("");
        for body_id in file_names
            .iter()
            .filter(|file_name| file_name.starts_with(&row_prefix))
        {
            let module_body_id = format!("{form_uuid}.0");
            if *body_id == module_body_id.as_str() {
                continue;
            }
            if let Some(row) = rows_by_file_name.get(*body_id)
                && let Ok(bytes) = decode_hex(&row.binary_hex)
                && parse_help_blob_pages(&bytes).is_some()
            {
                paths.insert(
                    (*body_id).to_string(),
                    SourceAsset {
                        primary_path: form_dir.join("Ext").join("Help.xml"),
                        kind: SourceAssetKind::Help,
                    },
                );
            }
        }
    }
    paths
}

#[allow(dead_code)]
fn parse_configuration_reference_blob(blob: &[u8]) -> Option<String> {
    let inflated = inflate_raw_deflate(blob).ok()?;
    let text = String::from_utf8(inflated).ok()?;
    let text = text.trim_start_matches('\u{feff}');
    parse_configuration_reference_text(text)
}

fn parse_configuration_reference_text(text: &str) -> Option<String> {
    if !text.trim_start().starts_with("{2,") {
        return None;
    }
    let marker = "{1,0,";
    let marker_start = text.find(marker)?;
    let uuid_start = marker_start + marker.len();
    let uuid_end = uuid_start + 36;
    let uuid = text.get(uuid_start..uuid_end)?;
    if !is_uuid_text(uuid) || !is_metadata_header_marker(text, uuid_end) {
        return None;
    }
    parse_metadata_header_from_text(text, uuid).map(|header| header.name)
}

fn extract_configuration_source_xml(
    text: &str,
    uuid: &str,
    object_refs: &BTreeMap<String, String>,
    source_version: InfobaseConfigSourceVersion,
) -> Option<String> {
    if !text.trim_start().starts_with("{2,") {
        return None;
    }
    let fields = split_1c_braced_fields(text, 0)?;
    if fields.first()?.trim() != "2" {
        return None;
    }
    let uuid_fields = split_1c_braced_fields(fields.get(1)?, 0)?;
    if uuid_fields.first()?.trim() != uuid {
        return None;
    }
    let marker = "{1,0,";
    let marker_start = text.find(marker)?;
    let header_uuid_start = marker_start + marker.len();
    let header_uuid_end = header_uuid_start + 36;
    let header_uuid = text.get(header_uuid_start..header_uuid_end)?;
    if !is_uuid_text(header_uuid) || !is_metadata_header_marker(text, header_uuid_end) {
        return None;
    }
    let mut header = parse_metadata_header_from_text(text, header_uuid)?;
    header.uuid = uuid.to_string();
    let properties =
        parse_configuration_properties_from_text(text, object_refs).unwrap_or_default();
    let child_objects = parse_configuration_child_objects(text, uuid, header_uuid);
    let mut xml = format_configuration_source_xml(&header, &properties, source_version);
    if !child_objects.is_empty() {
        let mut child_xml = String::new();
        for child_object in &child_objects {
            push_metadata_header_child_object_xml(
                &mut child_xml,
                child_object.tag,
                &child_object.header,
            );
        }
        insert_metadata_child_objects_xml(&mut xml, "Configuration", &child_xml);
    }
    Some(xml)
}

fn parse_configuration_properties_from_text(
    text: &str,
    object_refs: &BTreeMap<String, String>,
) -> Option<ConfigurationProperties> {
    let fields = configuration_root_fields(text)?;
    Some(ConfigurationProperties {
        name_prefix: fields
            .get(2)
            .and_then(|field| parse_1c_quoted_string(field.trim())),
        configuration_extension_compatibility_mode: fields
            .get(26)
            .and_then(|field| configuration_compatibility_mode_xml(field.trim())),
        default_run_mode: fields
            .get(3)
            .and_then(|field| configuration_default_run_mode_xml(field.trim())),
        brief_information: parse_configuration_localized_property(&fields, 4),
        detailed_information: parse_configuration_localized_property(&fields, 5),
        copyright: parse_configuration_localized_property(&fields, 6),
        vendor_information_address: parse_configuration_localized_property(&fields, 7),
        configuration_information_address: parse_configuration_localized_property(&fields, 8),
        default_style: parse_configuration_root_reference(&fields, 9, object_refs, "Style."),
        default_language: parse_configuration_root_reference(&fields, 10, object_refs, "Language."),
        script_variant: fields
            .get(13)
            .and_then(|field| configuration_script_variant_xml(field.trim())),
        default_roles: fields
            .get(39)
            .map(|field| parse_configuration_default_roles(field, object_refs))
            .unwrap_or_default(),
        vendor: fields
            .get(14)
            .and_then(|field| parse_1c_quoted_string(field.trim())),
        version: fields
            .get(15)
            .and_then(|field| parse_1c_quoted_string(field.trim())),
        update_catalog_address: fields
            .get(16)
            .and_then(|field| parse_1c_quoted_string(field.trim())),
        common_settings_storage: parse_configuration_root_reference_slot(
            &fields,
            22,
            object_refs,
            "SettingsStorage.",
        ),
        reports_user_settings_storage: parse_configuration_root_reference_slot(
            &fields,
            23,
            object_refs,
            "SettingsStorage.",
        ),
        reports_variants_storage: parse_configuration_root_reference_slot(
            &fields,
            24,
            object_refs,
            "SettingsStorage.",
        ),
        form_data_settings_storage: parse_configuration_root_reference_slot(
            &fields,
            25,
            object_refs,
            "SettingsStorage.",
        ),
        compatibility_mode: fields
            .get(43)
            .and_then(|field| configuration_compatibility_mode_xml(field.trim())),
    })
}

fn parse_configuration_default_roles(
    field: &str,
    object_refs: &BTreeMap<String, String>,
) -> Vec<String> {
    let Some(fields) = split_1c_braced_fields(field, 0) else {
        return Vec::new();
    };
    let Some(count) = fields
        .get(1)
        .and_then(|field| field.trim().parse::<usize>().ok())
    else {
        return Vec::new();
    };

    fields
        .iter()
        .skip(2)
        .take(count)
        .filter_map(|field| parse_design_time_reference(field, object_refs))
        .filter(|reference| reference.starts_with("Role."))
        .collect()
}

fn configuration_root_fields(text: &str) -> Option<Vec<&str>> {
    let start = text.find("{68,")?;
    split_1c_braced_fields(text, start)
}

fn parse_configuration_localized_property(fields: &[&str], index: usize) -> Vec<(String, String)> {
    fields
        .get(index)
        .map(|field| parse_1c_synonyms(field))
        .unwrap_or_default()
}

fn parse_configuration_root_reference(
    fields: &[&str],
    index: usize,
    object_refs: &BTreeMap<String, String>,
    expected_prefix: &str,
) -> Option<String> {
    parse_configuration_root_reference_slot(fields, index, object_refs, expected_prefix)?.value
}

fn parse_configuration_root_reference_slot(
    fields: &[&str],
    index: usize,
    object_refs: &BTreeMap<String, String>,
    expected_prefix: &str,
) -> Option<ConfigurationRootReference> {
    let field = fields.get(index)?.trim();
    if field == "00000000-0000-0000-0000-000000000000" {
        return Some(ConfigurationRootReference { value: None });
    }
    let uuid = parse_non_zero_uuid(field)?;
    let reference = object_refs.get(&uuid)?;
    reference
        .starts_with(expected_prefix)
        .then(|| ConfigurationRootReference {
            value: Some(reference.clone()),
        })
}

fn configuration_default_run_mode_xml(value: &str) -> Option<&'static str> {
    match value {
        "0" => Some("OrdinaryApplication"),
        "1" => Some("ManagedApplication"),
        _ => None,
    }
}

fn configuration_script_variant_xml(value: &str) -> Option<&'static str> {
    match value {
        "0" => Some("Russian"),
        "1" => Some("English"),
        _ => None,
    }
}

fn configuration_compatibility_mode_xml(value: &str) -> Option<String> {
    if let Some(value) = parse_1c_quoted_string(value) {
        return if value.is_empty() { None } else { Some(value) };
    }
    let version = value.parse::<u32>().ok()?;
    if version < 80000 {
        return None;
    }
    Some(format!(
        "Version{}_{}_{}",
        version / 10000,
        (version / 100) % 100,
        version % 100
    ))
}

struct ConfigurationChildObject {
    tag: &'static str,
    header: MetadataHeader,
}

fn parse_configuration_child_objects(
    text: &str,
    uuid: &str,
    header_uuid: &str,
) -> Vec<ConfigurationChildObject> {
    nested_headers_with_offsets_from_text(text, uuid, |_| true)
        .into_iter()
        .filter_map(|(header, marker_start)| {
            if header.uuid == header_uuid {
                return None;
            }
            configuration_child_object_tag(text, marker_start, &header.uuid)
                .map(|tag| ConfigurationChildObject { tag, header })
        })
        .collect()
}

fn configuration_child_object_tag(
    text: &str,
    marker_start: usize,
    child_uuid: &str,
) -> Option<&'static str> {
    let mut search_end = marker_start;
    let mut tag = None;
    while let Some(start) = text[..search_end].rfind('{') {
        search_end = start;
        let Some(end) = scan_1c_braced_value(text, start) else {
            continue;
        };
        if marker_start >= end {
            continue;
        }
        let object_text = &text[start..end];
        if object_text.contains("{68,") {
            continue;
        }
        let Some(fields) = split_1c_braced_fields(object_text, 0) else {
            continue;
        };
        let Some(code) = fields
            .first()
            .and_then(|field| field.trim().parse::<u32>().ok())
        else {
            continue;
        };
        if let Some((kind, _)) = metadata_source_for_object_text(code, object_text, child_uuid) {
            if matches!(kind, "CommonForm" | "CommonTemplate") {
                return None;
            }
            tag = Some(kind);
        }
    }
    tag
}

#[allow(dead_code)]
fn build_command_interface_reference_index(rows: &[ConfigRow]) -> BTreeMap<String, String> {
    let metadata_texts = build_metadata_text_rows(rows);
    build_command_interface_reference_index_from_texts(&metadata_texts)
}

fn build_command_interface_reference_index_from_texts(
    rows: &[MetadataTextRow],
) -> BTreeMap<String, String> {
    let row_entries = parallel::install(|| {
        rows.par_iter()
            .enumerate()
            .map(|(index, row)| (index, command_interface_reference_entries_from_text(row)))
            .collect::<Vec<_>>()
    })
    .unwrap_or_else(|_| {
        rows.iter()
            .enumerate()
            .map(|(index, row)| (index, command_interface_reference_entries_from_text(row)))
            .collect::<Vec<_>>()
    });
    let mut index = BTreeMap::new();
    for (_, entries) in row_entries {
        for (uuid, reference) in entries {
            index.insert(uuid, reference);
        }
    }
    index
}

fn command_interface_reference_entries_from_text(row: &MetadataTextRow) -> Vec<(String, String)> {
    let (Some(kind), Some(header)) = (row.kind.as_deref(), row.header.as_ref()) else {
        return Vec::new();
    };
    let mut entries = Vec::new();
    if kind == "CommonCommand" {
        entries.push((
            row.file_name.clone(),
            format!("CommonCommand.{}", header.name),
        ));
    }
    entries.extend(
        nested_command_headers_from_text(&row.text, &row.file_name)
            .into_iter()
            .map(|command| {
                (
                    command.uuid,
                    format!("{}.{}.Command.{}", kind, header.name, command.name),
                )
            }),
    );
    entries
}

#[allow(dead_code)]
fn parse_metadata_command_reference_blob(
    blob: &[u8],
    uuid: &str,
) -> Option<(String, MetadataHeader, String)> {
    let inflated = inflate_raw_deflate(blob).ok()?;
    let text = String::from_utf8(inflated).ok()?;
    let text = text.trim_start_matches('\u{feff}').to_string();
    let object_code = parse_metadata_object_code(&text)?;
    let kind = if object_code == 12 {
        "CommonModule"
    } else {
        metadata_source_for_text(object_code, &text, uuid)?.0
    };
    let header = parse_metadata_header_from_text(&text, uuid)?;
    Some((kind.to_string(), header, text))
}

fn parse_command_interface_blob(
    bytes: &[u8],
    command_refs: &BTreeMap<String, String>,
    metadata_refs: &BTreeMap<String, MetadataCommandReference>,
) -> Option<CommandInterface> {
    let inflated = inflate_raw_deflate(bytes).ok()?;
    let text = String::from_utf8(inflated).ok()?;
    let fields = split_1c_braced_fields(text.trim_start_matches('\u{feff}'), 0)?;
    if fields.first()?.trim() != "7" {
        return None;
    }

    parse_command_interface_order_fields(&fields, command_refs, metadata_refs)
        .or_else(|| parse_command_interface_subsystems_order_fields(&fields, metadata_refs))
        .or_else(|| parse_command_interface_visibility_fields(&fields, command_refs, metadata_refs))
}

fn parse_command_interface_order_fields(
    fields: &[&str],
    command_refs: &BTreeMap<String, String>,
    metadata_refs: &BTreeMap<String, MetadataCommandReference>,
) -> Option<CommandInterface> {
    if fields.get(1)?.trim() != "0" {
        return None;
    }
    let count = fields.get(4)?.trim().parse::<usize>().ok()?;
    let default_group_uuid = fields.get(5)?.trim();
    if !is_uuid_text(default_group_uuid) {
        return None;
    }
    let mut commands_order = Vec::with_capacity(count);
    let mut groups_order = Vec::<String>::new();
    let mut index = 6usize;
    for _ in 0..count {
        let command_ref = split_1c_braced_fields(fields.get(index)?, 0)?;
        index += 1;
        let code = command_ref.first()?.trim();
        let uuid = command_ref.get(1).map(|value| value.trim())?;
        if !code.chars().all(|ch| ch.is_ascii_digit()) || !is_uuid_text(uuid) {
            return None;
        }
        let group_uuid = match fields.get(index)?.trim() {
            "0" => default_group_uuid,
            value => value,
        };
        index += 1;
        if !is_uuid_text(group_uuid) {
            return None;
        }
        let name = command_interface_command_name(code, uuid, command_refs, metadata_refs);
        let command_group = command_interface_group_name(group_uuid, metadata_refs);
        if !groups_order.iter().any(|group| group == &command_group) {
            groups_order.push(command_group.clone());
        }
        commands_order.push(CommandInterfaceOrderEntry {
            name,
            command_group,
        });
    }

    Some(CommandInterface {
        commands_order,
        commands_placement: Vec::new(),
        groups_order,
        commands_visibility: Vec::new(),
        subsystems_order: Vec::new(),
    })
}

fn parse_command_interface_subsystems_order_fields(
    fields: &[&str],
    metadata_refs: &BTreeMap<String, MetadataCommandReference>,
) -> Option<CommandInterface> {
    if fields.get(1)?.trim() != "0"
        || fields.get(2)?.trim() != "0"
        || fields.get(3)?.trim() != "0"
        || fields.get(4)?.trim() != "1"
    {
        return None;
    }
    let count = fields.get(5)?.trim().parse::<usize>().ok()?;
    let mut subsystems_order = Vec::with_capacity(count);
    let mut index = 6usize;
    for _ in 0..count {
        let uuid = parse_non_zero_uuid(fields.get(index)?.trim())?;
        subsystems_order.push(command_interface_subsystem_name(&uuid, metadata_refs));
        index += 1;
    }

    Some(CommandInterface {
        commands_order: Vec::new(),
        commands_placement: Vec::new(),
        groups_order: Vec::new(),
        commands_visibility: Vec::new(),
        subsystems_order,
    })
}

fn parse_command_interface_visibility_fields(
    fields: &[&str],
    command_refs: &BTreeMap<String, String>,
    metadata_refs: &BTreeMap<String, MetadataCommandReference>,
) -> Option<CommandInterface> {
    let count = fields.get(2)?.trim().parse::<usize>().ok()?;
    let mut commands_visibility = Vec::with_capacity(count);
    let mut index = 3usize;
    for _ in 0..count {
        let command_ref = split_1c_braced_fields(fields.get(index)?, 0)?;
        index += 1;
        let code = command_ref.first()?.trim();
        if !code.chars().all(|ch| ch.is_ascii_digit()) {
            return None;
        }
        let common = parse_command_interface_common_flag(fields.get(index)?)?;
        index += 1;
        let name = if let Some(uuid) = command_ref.get(1).map(|value| value.trim()) {
            if !is_uuid_text(uuid) {
                return None;
            }
            command_interface_command_name(code, uuid, command_refs, metadata_refs)
        } else {
            code.to_string()
        };
        commands_visibility.push(CommandInterfaceVisibilityEntry { name, common });
    }

    let commands_placement =
        parse_command_interface_placement_tail(fields, &mut index, command_refs, metadata_refs)
            .unwrap_or_default();
    let commands_order =
        parse_command_interface_order_tail(fields, &mut index, command_refs, metadata_refs)
            .unwrap_or_default();
    let groups_order = parse_command_interface_groups_order_tail(fields, &mut index, metadata_refs)
        .unwrap_or_default();

    Some(CommandInterface {
        commands_order,
        commands_placement,
        groups_order,
        commands_visibility,
        subsystems_order: Vec::new(),
    })
}

fn parse_command_interface_placement_tail(
    fields: &[&str],
    index: &mut usize,
    command_refs: &BTreeMap<String, String>,
    metadata_refs: &BTreeMap<String, MetadataCommandReference>,
) -> Option<Vec<CommandInterfacePlacementEntry>> {
    if fields.get(*index)?.trim() != "1" {
        return None;
    }
    *index += 1;
    let count = fields.get(*index)?.trim().parse::<usize>().ok()?;
    *index += 1;
    let mut entries = Vec::with_capacity(count);
    for _ in 0..count {
        let name = parse_command_interface_command_name_field(
            fields.get(*index)?,
            command_refs,
            metadata_refs,
        )?;
        *index += 1;
        let command_group = command_interface_group_name(fields.get(*index)?.trim(), metadata_refs);
        *index += 1;
        let placement = command_interface_placement_name(fields.get(*index)?.trim())?;
        *index += 1;
        entries.push(CommandInterfacePlacementEntry {
            name,
            command_group,
            placement,
        });
    }
    Some(entries)
}

fn parse_command_interface_order_tail(
    fields: &[&str],
    index: &mut usize,
    command_refs: &BTreeMap<String, String>,
    metadata_refs: &BTreeMap<String, MetadataCommandReference>,
) -> Option<Vec<CommandInterfaceOrderEntry>> {
    if fields.get(*index)?.trim() != "1" {
        return None;
    }
    *index += 1;
    let count = fields.get(*index)?.trim().parse::<usize>().ok()?;
    *index += 1;
    let mut entries = Vec::with_capacity(count);
    for _ in 0..count {
        let command_group = command_interface_group_name(fields.get(*index)?.trim(), metadata_refs);
        *index += 1;
        let name = parse_command_interface_command_name_field(
            fields.get(*index)?,
            command_refs,
            metadata_refs,
        )?;
        *index += 1;
        entries.push(CommandInterfaceOrderEntry {
            name,
            command_group,
        });
    }
    Some(entries)
}

fn parse_command_interface_groups_order_tail(
    fields: &[&str],
    index: &mut usize,
    metadata_refs: &BTreeMap<String, MetadataCommandReference>,
) -> Option<Vec<String>> {
    if fields.get(*index)?.trim() == "0" {
        *index += 1;
    }
    if fields.get(*index)?.trim() != "1" {
        return None;
    }
    *index += 1;
    let count = fields.get(*index)?.trim().parse::<usize>().ok()?;
    *index += 1;
    let mut groups = Vec::with_capacity(count);
    for _ in 0..count {
        groups.push(command_interface_group_name(
            fields.get(*index)?.trim(),
            metadata_refs,
        ));
        *index += 1;
    }
    Some(groups)
}

fn parse_command_interface_command_name_field(
    field: &str,
    command_refs: &BTreeMap<String, String>,
    metadata_refs: &BTreeMap<String, MetadataCommandReference>,
) -> Option<String> {
    let command_ref = split_1c_braced_fields(field, 0)?;
    let code = command_ref.first()?.trim();
    if !code.chars().all(|ch| ch.is_ascii_digit()) {
        return None;
    }
    let uuid = command_ref.get(1).map(|value| value.trim())?;
    if !is_uuid_text(uuid) {
        return None;
    }
    Some(command_interface_command_name(
        code,
        uuid,
        command_refs,
        metadata_refs,
    ))
}

fn command_interface_placement_name(code: &str) -> Option<&'static str> {
    match code {
        "0" => Some("Auto"),
        "1" => Some("Manual"),
        _ => None,
    }
}

fn parse_command_interface_common_flag(value: &str) -> Option<bool> {
    if value.contains(r#"{"B",1}"#) {
        Some(true)
    } else if value.contains(r#"{"B",0}"#) {
        Some(false)
    } else {
        None
    }
}

fn command_interface_group_name(
    uuid: &str,
    metadata_refs: &BTreeMap<String, MetadataCommandReference>,
) -> String {
    if let Some(name) = common_command_group_name(uuid) {
        return name.to_string();
    }
    metadata_refs
        .get(uuid)
        .filter(|reference| reference.kind == "CommandGroup")
        .map(|reference| format!("CommandGroup.{}", reference.name))
        .unwrap_or_else(|| uuid.to_string())
}

fn command_interface_subsystem_name(
    uuid: &str,
    metadata_refs: &BTreeMap<String, MetadataCommandReference>,
) -> String {
    metadata_refs
        .get(uuid)
        .filter(|reference| reference.kind == "Subsystem")
        .map(|reference| format!("Subsystem.{}", reference.name))
        .unwrap_or_else(|| format!("Subsystem.{uuid}"))
}

fn parse_home_page_work_area_blob(
    bytes: &[u8],
    form_refs: &BTreeMap<String, FormSourceReference>,
) -> Option<HomePageWorkArea> {
    let inflated = inflate_raw_deflate(bytes).ok()?;
    let text = String::from_utf8(inflated).ok()?;
    parse_home_page_work_area_text(text.trim_start_matches('\u{feff}'), form_refs)
}

fn parse_home_page_work_area_text(
    text: &str,
    form_refs: &BTreeMap<String, FormSourceReference>,
) -> Option<HomePageWorkArea> {
    let fields = split_1c_braced_fields(text, 0)?;
    if fields.first()?.trim() != "1" {
        return None;
    }
    let template = home_page_work_area_template_name(fields.get(1)?.trim())?;
    let mut index = 2usize;
    let left_column = parse_home_page_work_area_column(&fields, &mut index, form_refs)?;
    let right_column = parse_home_page_work_area_column(&fields, &mut index, form_refs)?;

    Some(HomePageWorkArea {
        template,
        left_column,
        right_column,
    })
}

fn home_page_work_area_template_name(code: &str) -> Option<&'static str> {
    match code {
        "2" => Some("TwoColumnsVariableWidth"),
        _ => None,
    }
}

fn parse_home_page_work_area_column(
    fields: &[&str],
    index: &mut usize,
    form_refs: &BTreeMap<String, FormSourceReference>,
) -> Option<Vec<HomePageWorkAreaItem>> {
    let count = fields.get(*index)?.trim().parse::<usize>().ok()?;
    *index += 1;
    let mut items = Vec::with_capacity(count);
    for _ in 0..count {
        let item = parse_home_page_work_area_item(fields.get(*index)?, form_refs)?;
        *index += 1;
        items.push(item);
    }
    Some(items)
}

fn parse_home_page_work_area_item(
    field: &str,
    form_refs: &BTreeMap<String, FormSourceReference>,
) -> Option<HomePageWorkAreaItem> {
    let fields = split_1c_braced_fields(field, 0)?;
    let form_fields = split_1c_braced_fields(fields.get(1)?, 0)?;
    let form_uuid = parse_non_zero_uuid(form_fields.get(1)?.trim())?;
    let form = form_refs
        .get(&form_uuid)
        .and_then(form_source_reference_name)
        .unwrap_or(form_uuid);
    let height = fields.get(2)?.trim().to_string();
    let common = parse_command_interface_common_flag(fields.get(3)?)?;

    Some(HomePageWorkAreaItem {
        form,
        height,
        common,
    })
}

fn parse_client_application_interface_blob(bytes: &[u8]) -> Option<ClientApplicationInterface> {
    let inflated = inflate_raw_deflate(bytes).ok()?;
    let text = String::from_utf8(inflated).ok()?;
    parse_client_application_interface_text(text.trim_start_matches('\u{feff}'))
}

fn parse_client_application_interface_text(text: &str) -> Option<ClientApplicationInterface> {
    let fields = split_1c_braced_fields(text, 0)?;
    if fields.first()?.trim() != "1" {
        return None;
    }

    let mut top = None;
    let mut left = None;
    let mut index = 1usize;
    while index < fields.len() {
        let Some(area_fields) = fields
            .get(index)
            .and_then(|field| split_1c_braced_fields(field, 0))
        else {
            break;
        };
        if area_fields.len() < 3 || area_fields.first().map(|value| value.trim()) != Some("0") {
            break;
        }
        let area_code = area_fields.get(1)?.trim();
        let group = parse_client_application_interface_area(area_fields.get(2)?)?;
        match area_code {
            "1" => top = group,
            "3" => left = group,
            _ => {}
        }
        index += 1;
    }

    let mut panel_defs = Vec::new();
    while index + 1 < fields.len() {
        let code = fields.get(index)?.trim();
        if code == "0" {
            break;
        }
        let panel_def_fields = split_1c_braced_fields(fields.get(index + 1)?, 0)?;
        let panel_uuid = parse_non_zero_uuid(panel_def_fields.first()?.trim())?;
        panel_defs.push(panel_uuid);
        index += 2;
    }

    Some(ClientApplicationInterface {
        top,
        left,
        panel_defs,
    })
}

fn parse_client_application_interface_area(
    field: &str,
) -> Option<Option<ClientApplicationInterfaceGroup>> {
    let fields = split_1c_braced_fields(field, 0)?;
    if fields.first()?.trim() != "0" {
        return None;
    }
    let count = fields.get(1)?.trim().parse::<usize>().ok()?;
    if count == 0 {
        return Some(None);
    }
    let group = fields
        .get(3)
        .and_then(|field| parse_client_application_interface_group(field, true))?;
    Some(Some(group))
}

fn parse_client_application_interface_group(
    field: &str,
    with_id: bool,
) -> Option<ClientApplicationInterfaceGroup> {
    let fields = split_1c_braced_fields(field, 0)?;
    if fields.first()?.trim() != "0" {
        return None;
    }
    let id = if with_id {
        Some(parse_non_zero_uuid(fields.get(1)?.trim())?)
    } else {
        None
    };
    if fields.get(2)?.trim() != "0" {
        return None;
    }
    let children = parse_client_application_interface_children(fields.get(3)?)?;
    Some(ClientApplicationInterfaceGroup { id, children })
}

fn parse_client_application_interface_children(
    field: &str,
) -> Option<Vec<ClientApplicationInterfaceNode>> {
    let fields = split_1c_braced_fields(field, 0)?;
    if fields.first()?.trim() != "0" {
        return None;
    }
    let count = fields.get(1)?.trim().parse::<usize>().ok()?;
    let mut children = Vec::with_capacity(count);
    let mut index = 2usize;
    for _ in 0..count {
        let _layout_marker = fields.get(index)?;
        index += 1;
        let child_fields = split_1c_braced_fields(fields.get(index)?, 0)?;
        index += 1;
        if child_fields.len() >= 4
            && child_fields.first().map(|value| value.trim()) == Some("0")
            && child_fields.get(2).map(|value| value.trim()) == Some("0")
        {
            children.push(ClientApplicationInterfaceNode::Group(
                parse_client_application_interface_group(fields.get(index - 1)?, true)?,
            ));
        } else {
            let id = parse_non_zero_uuid(child_fields.get(1)?.trim())?;
            let uuid = parse_non_zero_uuid(child_fields.get(2)?.trim())?;
            children.push(ClientApplicationInterfaceNode::Group(
                ClientApplicationInterfaceGroup {
                    id: None,
                    children: vec![ClientApplicationInterfaceNode::Panel { id, uuid }],
                },
            ));
        }
    }
    Some(children)
}

fn parse_exchange_plan_content_blob(
    bytes: &[u8],
    object_refs: &BTreeMap<String, String>,
    type_index: &BTreeMap<String, String>,
    metadata_order: &BTreeMap<String, usize>,
) -> Result<Vec<ExchangePlanContentItem>> {
    let inflated = inflate_raw_deflate(bytes).context("failed to inflate ExchangePlanContent")?;
    let text = String::from_utf8(inflated).context("ExchangePlanContent is not valid UTF-8")?;
    let fields = split_1c_braced_fields(text.trim_start_matches('\u{feff}'), 0)
        .context("ExchangePlanContent body is not a braced 1C value")?;
    let marker = fields
        .first()
        .map(|field| field.trim())
        .context("ExchangePlanContent body is empty")?;
    if marker != "2" {
        bail!("unsupported ExchangePlanContent marker {marker}, expected 2");
    }
    let count = fields
        .get(1)
        .context("ExchangePlanContent body has no item count")?
        .trim()
        .parse::<usize>()
        .context("ExchangePlanContent item count is not numeric")?;
    let mut items = Vec::with_capacity(count);
    let mut index = 2usize;
    for item_index in 0..count {
        let object_slot = fields
            .get(index)
            .with_context(|| format!("ExchangePlanContent item {item_index} has no metadata id"))?;
        let object_id = parse_uuid_field(object_slot.trim()).with_context(|| {
            format!(
                "ExchangePlanContent item {item_index} metadata id is not a UUID: {}",
                object_slot.trim()
            )
        })?;
        let auto_record_slot = fields.get(index + 1).with_context(|| {
            format!("ExchangePlanContent item {item_index} has no AutoRecord value")
        })?;
        let auto_record = exchange_plan_auto_record_xml(auto_record_slot.trim());
        let metadata = object_refs
            .get(&object_id)
            .or_else(|| type_index.get(&object_id))
            .cloned()
            .with_context(|| {
                format!(
                    "ExchangePlanContent item {item_index} references unsupported metadata id {object_id}"
                )
            })?;
        items.push(ExchangePlanContentItem {
            metadata_id: object_id,
            metadata,
            auto_record,
        });
        index += 2;
    }

    items.sort_by_key(|item| {
        metadata_order
            .get(&item.metadata_id)
            .copied()
            .unwrap_or(usize::MAX)
    });

    Ok(items)
}

fn parse_business_process_flowchart_blob(bytes: &[u8]) -> Option<BusinessProcessFlowchart> {
    let inflated = inflate_raw_deflate(bytes).ok()?;
    let text = String::from_utf8(inflated).ok()?;
    parse_business_process_flowchart_text(text.trim_start_matches('\u{feff}'))
}

fn parse_business_process_flowchart_text(text: &str) -> Option<BusinessProcessFlowchart> {
    let fields = split_1c_braced_fields(text, 0)?;
    if fields.first()?.trim() != "5" {
        return None;
    }
    let item_count = fields.get(2)?.trim().parse::<usize>().ok()?;
    let mut raw_items = Vec::<(String, String)>::with_capacity(item_count);
    let mut names = BTreeMap::<String, String>::new();
    let mut index = 3usize;
    for _ in 0..item_count {
        let code = fields.get(index)?.trim().to_string();
        let body = fields.get(index + 1)?.to_string();
        let base = parse_flowchart_base(&code, &body)?;
        names.insert(base.id, base.name);
        raw_items.push((code, body));
        index += 2;
    }

    let mut items = Vec::with_capacity(item_count);
    for (z_order, (code, body)) in raw_items.into_iter().enumerate() {
        items.push(parse_flowchart_item(
            &code,
            &body,
            &names,
            z_order.to_string(),
        )?);
    }

    Some(BusinessProcessFlowchart { items })
}

fn parse_flowchart_item(
    code: &str,
    body: &str,
    names: &BTreeMap<String, String>,
    z_order: String,
) -> Option<FlowchartItem> {
    let fields = split_1c_braced_fields(body, 0)?;
    let base = parse_flowchart_base(code, body)?;
    let mut properties = FlowchartItemProperties {
        location: None,
        pivot_points: Vec::new(),
        from: None,
        to: None,
        font: FlowchartFont::default(),
        decorative_line: false,
        line_style: "Solid",
        begin_arrow: "None",
        end_arrow: "None",
        transparent: false,
        horizontal_align: "Center",
        explanation: None,
        task_description: None,
        true_port_index: None,
        false_port_index: None,
    };
    let mut events = Vec::new();
    let tag = match code {
        "0" => {
            parse_flowchart_shape_graphics(fields.get(2)?, &mut properties)?;
            properties.transparent = parse_flowchart_transparent(fields.get(2)?).unwrap_or(false);
            properties.horizontal_align = if properties.transparent {
                "Left"
            } else {
                "Center"
            };
            "Decoration"
        }
        "1" => {
            parse_flowchart_line_graphics(fields.get(6)?, &mut properties, names)?;
            let from_id = fields.get(2)?.trim();
            let to_id = fields.get(4)?.trim();
            if from_id != "-1"
                && let Some(from) = &mut properties.from
            {
                from.item = names.get(from_id).cloned().unwrap_or_default();
            }
            if to_id != "-1"
                && let Some(to) = &mut properties.to
            {
                to.item = names.get(to_id).cloned().unwrap_or_default();
            }
            properties.decorative_line = fields.get(5).map(|value| value.trim() == "1")?;
            properties.line_style = if properties.decorative_line {
                "Dashed"
            } else {
                "Solid"
            };
            properties.end_arrow = if properties.decorative_line
                && properties
                    .to
                    .as_ref()
                    .map(|end| end.item.is_empty())
                    .unwrap_or(true)
            {
                "None"
            } else {
                "Filled"
            };
            "ConnectionLine"
        }
        "2" => {
            parse_flowchart_shape_graphics(fields.get(2)?, &mut properties)?;
            events = parse_flowchart_named_events(fields.get(3)?, &["BeforeStart"])?;
            "Start"
        }
        "3" => {
            parse_flowchart_shape_graphics(fields.get(2)?, &mut properties)?;
            events = parse_flowchart_named_events(fields.get(3)?, &["OnComplete"])?;
            "Completion"
        }
        "4" => {
            parse_flowchart_shape_graphics(fields.get(2)?, &mut properties)?;
            properties.true_port_index = Some("3".to_string());
            properties.false_port_index = Some("1".to_string());
            events = parse_flowchart_named_events(fields.get(3)?, &["ConditionCheck"])?;
            "Condition"
        }
        "5" => {
            parse_flowchart_shape_graphics(fields.get(2)?, &mut properties)?;
            properties.explanation = fields.get(3).and_then(|value| parse_1c_string(value));
            properties.task_description = fields.get(7).and_then(|value| parse_1c_string(value));
            events = parse_flowchart_activity_events(fields.get(5)?)?;
            "Activity"
        }
        "7" => {
            parse_flowchart_shape_graphics(fields.get(2)?, &mut properties)?;
            "Split"
        }
        "8" => {
            parse_flowchart_shape_graphics(fields.get(2)?, &mut properties)?;
            "Join"
        }
        "9" => {
            parse_flowchart_shape_graphics(fields.get(2)?, &mut properties)?;
            events = parse_flowchart_named_events(fields.get(3)?, &["Processing"])?;
            "Processing"
        }
        _ => return None,
    };

    Some(FlowchartItem {
        tag,
        id: base.id,
        uuid: base.uuid,
        name: base.name,
        title: base.title,
        tab_order: base.tab_order,
        z_order,
        properties,
        events,
    })
}

fn parse_flowchart_base(code: &str, body: &str) -> Option<FlowchartBase> {
    let fields = split_1c_braced_fields(body, 0)?;
    let head = split_1c_braced_fields(fields.first()?, 0)?;
    let uuid = if matches!(code, "2" | "3" | "4" | "5" | "7" | "8" | "9") {
        head.get(2).map(|value| value.trim().to_string())
    } else {
        None
    }
    .filter(|value| is_uuid_text(value));
    let base_fields = if matches!(code, "2" | "3" | "4" | "5" | "7" | "8" | "9") {
        split_1c_braced_fields(head.first()?, 0)?
    } else {
        head
    };
    let id = base_fields.get(1)?.trim().to_string();
    let title = parse_flowchart_title(base_fields.get(2)?);
    let name = parse_1c_string(base_fields.get(3)?)?;
    let tab_order = base_fields.get(4)?.trim().to_string();

    Some(FlowchartBase {
        id,
        uuid,
        name,
        title,
        tab_order,
    })
}

fn parse_flowchart_shape_graphics(
    text: &str,
    properties: &mut FlowchartItemProperties,
) -> Option<()> {
    let outer = split_1c_braced_fields(text, 0)?;
    let wrapper = split_1c_braced_fields(outer.first()?, 0)?;
    let geometry = split_1c_braced_fields(wrapper.first()?, 0)?;
    if let Some(font) = geometry
        .first()
        .and_then(|style| parse_flowchart_style_font(style))
    {
        properties.font = font;
    }
    properties.location = Some(FlowchartLocation {
        left: geometry.get(2)?.trim().to_string(),
        top: geometry.get(3)?.trim().to_string(),
        right: geometry.get(4)?.trim().to_string(),
        bottom: geometry.get(5)?.trim().to_string(),
    });
    Some(())
}

fn parse_flowchart_line_graphics(
    text: &str,
    properties: &mut FlowchartItemProperties,
    names: &BTreeMap<String, String>,
) -> Option<()> {
    let outer = split_1c_braced_fields(text, 0)?;
    let geometry = split_1c_braced_fields(outer.first()?, 0)?;
    if let Some(font) = geometry
        .first()
        .and_then(|style| parse_flowchart_style_font(style))
    {
        properties.font = font;
    }
    let point_count = geometry.get(2)?.trim().parse::<usize>().ok()?;
    let mut points = Vec::with_capacity(point_count);
    let mut index = 3usize;
    for _ in 0..point_count {
        points.push(FlowchartPoint {
            x: geometry.get(index)?.trim().to_string(),
            y: geometry.get(index + 1)?.trim().to_string(),
        });
        index += 2;
    }
    properties.pivot_points = points;
    properties.line_style = parse_flowchart_line_style(geometry.get(index)?).unwrap_or("Solid");
    index += 2;
    let from_port = geometry.get(index)?.trim().to_string();
    let to_port = geometry.get(index + 1)?.trim().to_string();
    properties.from = Some(FlowchartConnectionEnd {
        item: String::new(),
        port_index: from_port,
    });
    properties.to = Some(FlowchartConnectionEnd {
        item: String::new(),
        port_index: to_port,
    });
    if geometry.get(index + 2).map(|value| value.trim() == "1") == Some(true) {
        properties.end_arrow = "Filled";
    }
    let _ = names;
    Some(())
}

impl Default for FlowchartFont {
    fn default() -> Self {
        Self {
            reference: "sys:DefaultGUIFont".to_string(),
            kind: "WindowsFont",
            height: None,
            bold: false,
            italic: false,
            underline: false,
            strikeout: false,
            scale: None,
        }
    }
}

fn parse_flowchart_style_font(style: &str) -> Option<FlowchartFont> {
    let fields = split_1c_braced_fields(style, 0)?;
    if fields.first()?.trim() != "7" {
        return None;
    }
    parse_flowchart_font_tuple(fields.get(4)?)
}

fn parse_flowchart_font_tuple(text: &str) -> Option<FlowchartFont> {
    let fields = split_1c_braced_fields(text, 0)?;
    if fields.first()?.trim() != "7" {
        return None;
    }
    let kind = fields.get(1).map(|field| field.trim()).unwrap_or("1");
    let (reference, kind_xml) = match kind {
        "1" => ("sys:DefaultGUIFont".to_string(), "WindowsFont"),
        "2" => {
            let reference = fields
                .get(3)
                .and_then(|field| {
                    split_1c_braced_fields(field, 0)?
                        .first()
                        .and_then(|code| code.trim().parse::<i32>().ok())
                })
                .and_then(standard_style_item_for_code)
                .map(|(_, name)| format!("style:{name}"))
                .unwrap_or_else(|| "style:TextFont".to_string());
            (reference, "StyleItem")
        }
        _ => return None,
    };
    let height = font_height_xml(fields.get(2).map(|field| field.trim()));
    let (weight, italic, underline, strikeout, scale) = if fields.len() >= 10 {
        (
            fields
                .get(4)
                .and_then(|field| field.trim().parse::<i32>().ok())
                .unwrap_or(400),
            fields
                .get(5)
                .and_then(|field| parse_1c_bool_flag(field.trim()))
                .unwrap_or(false),
            fields
                .get(6)
                .and_then(|field| parse_1c_bool_flag(field.trim()))
                .unwrap_or(false),
            fields
                .get(7)
                .and_then(|field| parse_1c_bool_flag(field.trim()))
                .unwrap_or(false),
            fields.get(9).map(|field| field.trim()).unwrap_or("100"),
        )
    } else {
        (
            400,
            false,
            false,
            false,
            fields.get(5).map(|field| field.trim()).unwrap_or("100"),
        )
    };
    let scale = (scale != "100").then(|| scale.to_string());
    Some(FlowchartFont {
        reference,
        kind: kind_xml,
        height,
        bold: weight >= 700,
        italic,
        underline,
        strikeout,
        scale,
    })
}

fn parse_flowchart_line_style(text: &str) -> Option<&'static str> {
    let fields = split_1c_braced_fields(text, 0)?;
    match fields.get(3)?.trim() {
        "2" => Some("Dashed"),
        _ => Some("Solid"),
    }
}

fn parse_flowchart_transparent(text: &str) -> Option<bool> {
    let outer = split_1c_braced_fields(text, 0)?;
    let wrapper = split_1c_braced_fields(outer.first()?, 0)?;
    let style = split_1c_braced_fields(wrapper.first()?, 0)?;
    let flags = split_1c_braced_fields(style.first()?, 0)?;
    Some(flags.get(11)?.trim() == "1")
}

fn parse_flowchart_activity_events(text: &str) -> Option<Vec<FlowchartEvent>> {
    let handlers = parse_flowchart_event_handlers(text)?;
    Some(vec![
        FlowchartEvent {
            name: "InteractiveActivationProcessing",
            handler: None,
        },
        FlowchartEvent {
            name: "BeforeCreateTasks",
            handler: handlers.get(&1).cloned(),
        },
        FlowchartEvent {
            name: "OnCreateTask",
            handler: handlers.get(&2).cloned(),
        },
        FlowchartEvent {
            name: "OnExecute",
            handler: handlers.get(&3).cloned(),
        },
        FlowchartEvent {
            name: "CheckExecutionProcessing",
            handler: None,
        },
        FlowchartEvent {
            name: "BeforeExecute",
            handler: None,
        },
        FlowchartEvent {
            name: "BeforeExecuteInteractively",
            handler: None,
        },
    ])
}

fn parse_flowchart_named_events(text: &str, names: &[&'static str]) -> Option<Vec<FlowchartEvent>> {
    let handlers = parse_flowchart_event_handlers(text)?;
    Some(
        names
            .iter()
            .enumerate()
            .map(|(index, name)| FlowchartEvent {
                name,
                handler: handlers.get(&(index as i32)).cloned(),
            })
            .collect(),
    )
}

fn parse_flowchart_event_handlers(text: &str) -> Option<BTreeMap<i32, String>> {
    let fields = split_1c_braced_fields(text, 0)?;
    let count = fields.first()?.trim().parse::<usize>().ok()?;
    let mut handlers = BTreeMap::new();
    for field in fields.iter().skip(1).take(count) {
        let event = split_1c_braced_fields(field, 0)?;
        let index = event.first()?.trim().parse::<i32>().ok()?;
        let handler = parse_1c_string(event.get(1)?)?;
        handlers.insert(index, handler);
    }
    Some(handlers)
}

fn parse_flowchart_title(text: &str) -> Vec<(String, String)> {
    let Some(fields) = split_1c_braced_fields(text, 0) else {
        return Vec::new();
    };
    let count = fields
        .get(1)
        .and_then(|value| value.trim().parse::<usize>().ok())
        .unwrap_or(0);
    fields
        .iter()
        .skip(2)
        .take(count)
        .filter_map(|field| {
            let pair = split_1c_braced_fields(field, 0)?;
            Some((
                parse_1c_string(pair.first()?)?,
                parse_1c_string(pair.get(1)?)?,
            ))
        })
        .collect()
}

fn parse_1c_string(text: &str) -> Option<String> {
    let text = text.trim();
    let inner = text.strip_prefix('"')?.strip_suffix('"')?;
    Some(inner.replace("\"\"", "\""))
}

fn exchange_plan_auto_record_xml(value: &str) -> &'static str {
    match value {
        "0" => "Deny",
        "1" => "Allow",
        "2" => "Auto",
        _ => "Auto",
    }
}

fn command_interface_command_name(
    code: &str,
    uuid: &str,
    command_refs: &BTreeMap<String, String>,
    metadata_refs: &BTreeMap<String, MetadataCommandReference>,
) -> String {
    if let Some(name) = command_refs.get(uuid) {
        return name.clone();
    }
    if let Some(metadata) = metadata_refs.get(uuid) {
        if matches!(code, "0" | "100")
            && let Some(standard) = command_interface_standard_command(&metadata.kind)
        {
            return format!(
                "{}.{}.StandardCommand.{standard}",
                metadata.kind, metadata.name
            );
        }
        if code == "1" {
            return format!("{}.{}.StandardCommand.Create", metadata.kind, metadata.name);
        }
    }

    format!("{code}:{uuid}")
}

fn command_interface_standard_command(kind: &str) -> Option<&'static str> {
    match kind {
        "DataProcessor" | "Report" | "CommonForm" => Some("Open"),
        "AccountingRegister"
        | "AccumulationRegister"
        | "BusinessProcess"
        | "Catalog"
        | "ChartOfAccounts"
        | "ChartOfCalculationTypes"
        | "ChartOfCharacteristicTypes"
        | "Document"
        | "DocumentJournal"
        | "Enum"
        | "ExchangePlan"
        | "InformationRegister"
        | "Task" => Some("OpenList"),
        _ => None,
    }
}

fn parse_role_rights_blob(
    bytes: &[u8],
    object_refs: &BTreeMap<String, String>,
    field_refs: &BTreeMap<String, String>,
) -> Option<RoleRights> {
    let inflated = inflate_raw_deflate(bytes).ok()?;
    let text = String::from_utf8(inflated).ok()?;
    let fields = split_1c_braced_fields(text.trim_start_matches('\u{feff}'), 0)?;
    if fields.first()?.trim() != "10" {
        return None;
    }
    let object_fields = split_1c_braced_fields(fields.get(1)?, 0)?;
    let count = object_fields.first()?.trim().parse::<usize>().ok()?;
    if object_fields.len() != count + 1 {
        return None;
    }

    let mut objects = Vec::with_capacity(count);
    for (serialized_index, object_field) in object_fields.iter().skip(1).enumerate() {
        let entry = split_1c_braced_fields(object_field, 0)?;
        if entry.len() != 2 {
            return None;
        }

        let object_ref = split_1c_braced_fields(entry[0], 0)?;
        let object_uuid = object_ref.get(1)?.trim();
        if !is_uuid_text(object_uuid) {
            return None;
        }
        let object_name = role_object_ref_name(&object_ref, object_refs)?;

        let rights = parse_role_object_rights(entry[1], field_refs)?;
        let intra_uuid_order =
            role_rights_object_intra_uuid_order(&object_ref, &object_name).unwrap_or(0);
        objects.push((
            object_uuid.to_string(),
            intra_uuid_order,
            serialized_index,
            RoleObjectRights {
                name: object_name,
                rights,
            },
        ));
    }
    objects.sort_by_key(|(sort_uuid, intra_uuid_order, serialized_index, _)| {
        (sort_uuid.clone(), *intra_uuid_order, *serialized_index)
    });
    let mut normalized_objects = objects
        .into_iter()
        .map(|(_, _, _, object)| object)
        .collect::<Vec<_>>();
    normalize_chart_of_characteristic_type_tabular_attribute_role_refs(&mut normalized_objects);

    let restriction_templates = parse_role_restriction_templates(fields.get(2)?)?;
    let set_for_new_objects = parse_role_bool_field(fields.get(3)?)?;
    let set_for_attributes_by_default = parse_role_bool_field_or_default(&fields, 4, true)?;
    let independent_rights_of_child_objects = parse_role_bool_field_or_default(&fields, 5, false)?;
    Some(RoleRights {
        set_for_new_objects,
        set_for_attributes_by_default,
        independent_rights_of_child_objects,
        objects: normalized_objects,
        restriction_templates,
    })
}

fn normalize_chart_of_characteristic_type_tabular_attribute_role_refs(
    objects: &mut [RoleObjectRights],
) {
    let object_names = objects
        .iter()
        .map(|object| object.name.clone())
        .collect::<BTreeSet<_>>();
    let mut counts = HashMap::<String, usize>::new();
    for object in objects.iter() {
        *counts.entry(object.name.clone()).or_insert(0) += 1;
    }
    let mut seen = HashMap::<String, usize>::new();
    for object in objects {
        let Some((owner, attribute)) =
            chart_of_characteristic_type_attribute_role_name_parts(&object.name)
        else {
            continue;
        };
        let Some((tabular_section, rename_singleton)) =
            chart_of_characteristic_type_tabular_section_for_role_attribute(attribute)
        else {
            continue;
        };
        let tabular_section_name =
            format!("ChartOfCharacteristicTypes.{owner}.TabularSection.{tabular_section}");
        if !object_names.contains(&tabular_section_name) {
            continue;
        }
        let entry = seen.entry(object.name.clone()).or_insert(0);
        let occurrence = *entry;
        *entry += 1;
        let total = counts.get(&object.name).copied().unwrap_or(0);
        if rename_singleton || (total > 1 && occurrence == 0) {
            object.name = format!("{tabular_section_name}.Attribute.{attribute}");
        }
    }
}

fn chart_of_characteristic_type_attribute_role_name_parts(name: &str) -> Option<(&str, &str)> {
    let prefix = "ChartOfCharacteristicTypes.";
    let rest = name.strip_prefix(prefix)?;
    let (owner, remainder) = rest.split_once(".Attribute.")?;
    (!owner.contains('.') && !remainder.contains('.')).then_some((owner, remainder))
}

fn chart_of_characteristic_type_tabular_section_for_role_attribute(
    attribute: &str,
) -> Option<(&'static str, bool)> {
    match attribute {
        "Значение" | "Свойство" | "ТекстоваяСтрока" => {
            Some(("ДополнительныеРеквизиты", true))
        }
        "ХозяйственнаяОперация" => {
            Some(("ДоступныеХозяйственныеОперации", true))
        }
        "ПланСчетов" => Some(("НастройкиМеждународногоУчета", true)),
        "СчетУчета" | "Субконто1" | "Субконто2" | "Субконто3" => {
            Some(("НастройкиМеждународногоУчета", false))
        }
        _ => None,
    }
}

fn role_rights_object_intra_uuid_order(fields: &[&str], object_name: &str) -> Option<usize> {
    let kind_code = fields.get(2).map(|field| field.trim());
    let slot_code = fields.get(3).map(|field| field.trim())?;
    role_standard_attribute_sort_order(object_name, kind_code, slot_code)
}

fn role_object_ref_name(fields: &[&str], object_refs: &BTreeMap<String, String>) -> Option<String> {
    let uuid = fields.get(1)?.trim();
    if !is_uuid_text(uuid) {
        return None;
    }
    let base_name = object_refs
        .get(uuid)
        .cloned()
        .unwrap_or_else(|| uuid.to_string());
    let kind_code = fields.get(2).map(|field| field.trim());
    let slot_code = fields.get(3).map(|field| field.trim());
    role_standard_attribute_ref_name(&base_name, kind_code, slot_code).or(Some(base_name))
}

fn role_standard_attribute_ref_name(
    base_name: &str,
    kind_code: Option<&str>,
    slot_code: Option<&str>,
) -> Option<String> {
    if kind_code != Some("1") {
        return None;
    }
    let slot = role_standard_attribute_slot(slot_code?)?;
    let slot_index = usize::try_from(slot).ok();
    let (kind, _) = base_name.split_once('.')?;
    let attribute = role_standard_attribute_descriptor(kind, slot, slot_index)?.0;
    Some(format!("{base_name}.StandardAttribute.{attribute}"))
}

fn role_standard_attribute_slot(slot_code: &str) -> Option<isize> {
    slot_code.parse::<isize>().ok().or_else(|| {
        split_1c_braced_fields(slot_code, 0)?
            .first()?
            .trim()
            .parse::<isize>()
            .ok()
    })
}

fn role_standard_attribute_sort_order(
    base_name: &str,
    kind_code: Option<&str>,
    slot_code: &str,
) -> Option<usize> {
    if kind_code != Some("1") || !slot_code.trim_start().starts_with('{') {
        return None;
    }
    let slot = role_standard_attribute_slot(slot_code)?;
    let slot_index = usize::try_from(slot).ok();
    let (kind, _) = base_name.split_once('.')?;
    role_standard_attribute_descriptor(kind, slot, slot_index).map(|(_, order)| order)
}

fn role_standard_attribute_descriptor(
    kind: &str,
    slot: isize,
    slot_index: Option<usize>,
) -> Option<(&'static str, usize)> {
    match kind {
        "Catalog" => match slot {
            -13 => Some(("PredefinedDataName", 1)),
            -10 => Some(("Predefined", 2)),
            -8 => Some(("Ref", 3)),
            -7 => Some(("DeletionMark", 4)),
            -6 => Some(("IsFolder", 5)),
            -5 => Some(("Owner", 6)),
            -4 => Some(("Parent", 7)),
            -3 => Some(("Description", 8)),
            -2 => Some(("Code", 9)),
            _ => [
                ("PredefinedDataName", 1),
                ("Predefined", 2),
                ("Ref", 3),
                ("DeletionMark", 4),
                ("IsFolder", 5),
                ("Owner", 6),
                ("Parent", 7),
                ("Description", 8),
                ("Code", 9),
            ]
            .get(slot_index?)
            .copied(),
        },
        "ChartOfCharacteristicTypes" => match slot {
            -14 => Some(("PredefinedDataName", 1)),
            -11 => Some(("ValueType", 2)),
            -9 => Some(("Description", 3)),
            -8 => Some(("Code", 4)),
            -7 => Some(("IsFolder", 5)),
            -6 => Some(("Parent", 6)),
            -5 => Some(("Predefined", 7)),
            -4 => Some(("DeletionMark", 8)),
            -2 => Some(("Ref", 9)),
            _ => [
                ("PredefinedDataName", 1),
                ("ValueType", 2),
                ("Description", 3),
                ("Code", 4),
                ("IsFolder", 5),
                ("Parent", 6),
                ("Predefined", 7),
                ("DeletionMark", 8),
                ("Ref", 9),
            ]
            .get(slot_index?)
            .copied(),
        },
        "Document" => slot_index
            .and_then(|index| {
                [
                    ("Posted", 1),
                    ("Ref", 2),
                    ("DeletionMark", 3),
                    ("Date", 4),
                    ("Number", 5),
                ]
                .get(index)
                .copied()
            })
            .or(match slot {
                -7 => Some(("Number", 5)),
                -5 => Some(("Date", 4)),
                -4 => Some(("DeletionMark", 3)),
                -3 => Some(("Ref", 2)),
                -2 => Some(("Posted", 1)),
                _ => None,
            }),
        "ExchangePlan" => match slot {
            -14 => Some(("ExchangeDate", 1)),
            -13 => Some(("ThisNode", 2)),
            -10 => Some(("ReceivedNo", 3)),
            -9 => Some(("SentNo", 4)),
            -6 => Some(("Ref", 5)),
            -4 => Some(("DeletionMark", 6)),
            -3 => Some(("Description", 7)),
            -2 => Some(("Code", 8)),
            _ => [
                ("ExchangeDate", 1),
                ("ThisNode", 2),
                ("ReceivedNo", 3),
                ("SentNo", 4),
                ("Ref", 5),
                ("DeletionMark", 6),
                ("Description", 7),
                ("Code", 8),
            ]
            .get(slot_index?)
            .copied(),
        },
        "AccumulationRegister" => match slot {
            -9 => Some(("RecordType", 1)),
            0 | -5 => Some(("Active", 2)),
            1 | -2 => Some(("Period", 5)),
            2 | -3 => Some(("Recorder", 4)),
            3 | -4 => Some(("LineNumber", 3)),
            _ => None,
        },
        "AccountingRegister" | "CalculationRegister" | "InformationRegister" => match slot {
            0 | -5 => Some(("Active", 1)),
            1 | -2 => Some(("Period", 4)),
            2 | -3 => Some(("Recorder", 3)),
            3 | -4 => Some(("LineNumber", 2)),
            _ => None,
        },
        _ => None,
    }
}

fn parse_role_object_rights(
    value: &str,
    field_refs: &BTreeMap<String, String>,
) -> Option<Vec<RoleRight>> {
    let fields = split_1c_braced_fields(value, 0)?;
    match fields.first()?.trim() {
        "0" if (fields.len() - 1) % 2 == 0 => {
            parse_role_right_pairs(&fields, 1, (fields.len() - 1) / 2, &BTreeMap::new())
        }
        "0" => None,
        "1" => {
            let count = fields.get(1)?.trim().parse::<usize>().ok()?;
            let pairs_start = 2usize;
            let restrictions_count_index = pairs_start.checked_add(count.checked_mul(2)?)?;
            if fields.len() <= restrictions_count_index {
                return None;
            }
            let restrictions = parse_role_right_restrictions(
                fields.get(restrictions_count_index)?.trim(),
                &fields[restrictions_count_index + 1..],
                field_refs,
            )?;
            parse_role_right_pairs(&fields, pairs_start, count, &restrictions)
        }
        _ => None,
    }
}

fn parse_role_right_pairs(
    fields: &[&str],
    start: usize,
    count: usize,
    restrictions: &BTreeMap<String, RoleRightRestriction>,
) -> Option<Vec<RoleRight>> {
    let mut rights = Vec::with_capacity(count);
    for index in 0..count {
        let offset = start.checked_add(index.checked_mul(2)?)?;
        let right_uuid = fields.get(offset)?.trim();
        if !is_uuid_text(right_uuid) {
            return None;
        }
        let value = parse_role_right_value(fields.get(offset + 1)?.trim())?;
        rights.push(RoleRight {
            name: role_right_name(right_uuid)?.to_string(),
            value,
            restriction_by_condition: restrictions.get(right_uuid).cloned(),
        });
    }
    Some(rights)
}

fn parse_role_bool_field(value: &str) -> Option<bool> {
    match value.trim() {
        "0" | "4294967295" => Some(false),
        "1" => Some(true),
        _ => None,
    }
}

fn parse_role_bool_field_or_default(fields: &[&str], index: usize, default: bool) -> Option<bool> {
    fields
        .get(index)
        .map_or(Some(default), |value| parse_role_bool_field(value))
}

fn parse_role_right_value(value: &str) -> Option<bool> {
    match value {
        "-1" | "0" => Some(false),
        "1" => Some(true),
        _ => None,
    }
}

fn parse_role_right_restrictions(
    count_text: &str,
    values: &[&str],
    field_refs: &BTreeMap<String, String>,
) -> Option<BTreeMap<String, RoleRightRestriction>> {
    let count = count_text.parse::<usize>().ok()?;
    let mut restrictions = BTreeMap::new();
    if count == 0 {
        if !values.is_empty() {
            return None;
        }
        return Some(restrictions);
    }
    if values.len() == count {
        for entry in values {
            let pair = split_1c_braced_fields(entry, 0)?;
            if pair.len() != 2 {
                return None;
            }
            let right_uuid = pair.first()?.trim();
            if !is_uuid_text(right_uuid) {
                return None;
            }
            let condition = parse_role_restriction_condition(pair.get(1)?, field_refs)?;
            restrictions.insert(right_uuid.to_string(), condition);
        }
        return Some(restrictions);
    }
    if values.len() != 1 {
        return None;
    }
    let entries = split_1c_braced_fields(values[0], 0)?;
    if entries.len() == count * 2
        && entries
            .first()
            .is_some_and(|entry| is_uuid_text(entry.trim()))
    {
        for entry in entries.chunks(2) {
            let right_uuid = entry.first()?.trim();
            let condition = parse_role_restriction_condition(entry.get(1)?, field_refs)?;
            restrictions.insert(right_uuid.to_string(), condition);
        }
        return Some(restrictions);
    }
    if entries.len() != count {
        return None;
    }
    for entry in entries {
        let pair = split_1c_braced_fields(entry, 0)?;
        if pair.len() != 2 {
            return None;
        }
        let right_uuid = pair.first()?.trim();
        if !is_uuid_text(right_uuid) {
            return None;
        }
        let condition = parse_role_restriction_condition(pair.get(1)?, field_refs)?;
        restrictions.insert(right_uuid.to_string(), condition);
    }
    Some(restrictions)
}

fn parse_role_restriction_condition(
    value: &str,
    field_refs: &BTreeMap<String, String>,
) -> Option<RoleRightRestriction> {
    let wrapper = split_1c_braced_fields(value, 0)?;
    match wrapper.first()?.trim() {
        "1" => parse_role_restriction_condition_body(wrapper.get(1)?),
        "2" => {
            let mut restriction = parse_role_restriction_condition_body(wrapper.get(2)?)?;
            let field = parse_role_restriction_field(wrapper.get(2)?, field_refs)?;
            restriction.field = Some(field);
            Some(restriction)
        }
        _ => None,
    }
}

fn parse_role_restriction_condition_body(value: &str) -> Option<RoleRightRestriction> {
    let condition_fields = split_1c_braced_fields(value, 0)?;
    if condition_fields.first()?.trim() != "1" {
        return None;
    }
    parse_1c_quoted_string_with_len(condition_fields.get(1)?.trim()).map(|(condition, _)| {
        RoleRightRestriction {
            field: None,
            condition,
        }
    })
}

fn parse_role_restriction_field(
    value: &str,
    field_refs: &BTreeMap<String, String>,
) -> Option<String> {
    if let Some((_, name)) = field_refs
        .iter()
        .find(|(uuid, _)| value.contains(uuid.as_str()))
    {
        return Some(name.clone());
    }
    if let Some(field) = parse_role_restriction_condition_body_field(value) {
        return Some(field);
    }
    let field_wrapper = split_1c_braced_fields(value, 0)?;
    if field_wrapper.first()?.trim() != "0" {
        return None;
    }
    let field_fields = split_1c_braced_fields(field_wrapper.get(1)?, 0)?;
    if field_fields.first()?.trim() != "1" {
        return None;
    }
    parse_1c_quoted_string_with_len(field_fields.get(1)?.trim()).map(|(value, _)| value)
}

fn parse_role_restriction_condition_body_field(value: &str) -> Option<String> {
    let condition_fields = split_1c_braced_fields(value, 0)?;
    if condition_fields.first()?.trim() != "1" {
        return None;
    }
    let field_payload = condition_fields.get(3)?;
    parse_role_restriction_field_payload(field_payload)
}

fn parse_role_restriction_field_payload(value: &str) -> Option<String> {
    if let Some(value) = parse_1c_quoted_string(value.trim()) {
        return Some(value);
    }
    let fields = split_1c_braced_fields(value, 0)?;
    if fields.first()?.trim() == "1" {
        return fields
            .get(1)
            .and_then(|field| parse_1c_quoted_string(field.trim()));
    }
    fields
        .iter()
        .find_map(|field| parse_role_restriction_field_payload(field))
}

fn parse_role_restriction_templates(value: &str) -> Option<Vec<RoleRestrictionTemplate>> {
    let fields = split_1c_braced_fields(value, 0)?;
    let count = fields.first()?.trim().parse::<usize>().ok()?;
    if fields.len() != count + 1 {
        return None;
    }
    let mut templates = Vec::with_capacity(count);
    for field in fields.iter().skip(1) {
        let template = split_1c_braced_fields(field, 0)?;
        if template.len() != 2 {
            return None;
        }
        let name = parse_1c_quoted_string_with_len(template.first()?.trim())?.0;
        let condition = parse_1c_quoted_string_with_len(template.get(1)?.trim())?.0;
        templates.push(RoleRestrictionTemplate { name, condition });
    }
    Some(templates)
}

fn role_right_name(uuid: &str) -> Option<&'static str> {
    ROLE_RIGHT_NAMES_BY_UUID.get(uuid).copied()
}

static ROLE_RIGHT_NAMES_BY_UUID: LazyLock<HashMap<&'static str, &'static str>> =
    LazyLock::new(|| ROLE_RIGHT_NAMES.iter().copied().collect());

