fn simple_metadata_form_template_child_objects_xml(
    kind: &str,
    owner_folder: &str,
    owner_name: &str,
    text: &str,
    form_refs: &BTreeMap<String, FormSourceReference>,
    template_refs: &BTreeMap<String, TemplateSourceReference>,
) -> String {
    if !metadata_kind_uses_simple_form_template_child_objects(kind) {
        return String::new();
    }

    let mut xml = String::new();
    for form in owned_metadata_form_names_in_text_order(text, owner_folder, owner_name, form_refs) {
        xml.push_str(&format!(
            "\t\t\t<Form>{}</Form>\r\n",
            escape_xml_element_text(&form)
        ));
    }
    for template in
        owned_metadata_template_names_in_text_order(text, owner_folder, owner_name, template_refs)
    {
        xml.push_str(&format!(
            "\t\t\t<Template>{}</Template>\r\n",
            escape_xml_element_text(&template)
        ));
    }
    xml
}

fn metadata_kind_uses_simple_form_template_child_objects(kind: &str) -> bool {
    matches!(
        kind,
        "AccumulationRegister"
            | "AccountingRegister"
            | "BusinessProcess"
            | "CalculationRegister"
            | "DocumentJournal"
            | "ExchangePlan"
            | "InformationRegister"
            | "SettingsStorage"
            | "Task"
    )
}

fn owned_metadata_template_names_in_text_order(
    text: &str,
    owner_folder: &str,
    owner_name: &str,
    template_refs: &BTreeMap<String, TemplateSourceReference>,
) -> Vec<String> {
    let mut names = Vec::new();
    let mut seen = BTreeSet::new();
    for uuid in uuid_like_values_in_text_order(text) {
        let Some(template_ref) = template_refs.get(&uuid) else {
            continue;
        };
        if template_ref.kind != "Template"
            || !is_owned_metadata_child_path(
                &template_ref.relative_path,
                owner_folder,
                owner_name,
                "Templates",
            )
        {
            continue;
        }
        let Some(name) = source_path_file_stem(&template_ref.relative_path) else {
            continue;
        };
        if seen.insert(name.clone()) {
            names.push(name);
        }
    }

    let mut path_names = template_refs
        .values()
        .filter(|template_ref| {
            template_ref.kind == "Template"
                && is_owned_metadata_child_path(
                    &template_ref.relative_path,
                    owner_folder,
                    owner_name,
                    "Templates",
                )
        })
        .filter_map(|template_ref| {
            source_path_file_stem(&template_ref.relative_path)
                .map(|name| (template_ref.relative_path.clone(), name))
        })
        .collect::<Vec<_>>();
    path_names.sort_by(|(left_path, _), (right_path, _)| left_path.cmp(right_path));
    for (_, name) in path_names {
        if seen.insert(name.clone()) {
            names.push(name);
        }
    }

    names
}

fn owned_metadata_form_names_in_text_order(
    text: &str,
    owner_folder: &str,
    owner_name: &str,
    form_refs: &BTreeMap<String, FormSourceReference>,
) -> Vec<String> {
    let mut names = Vec::new();
    let mut seen = BTreeSet::new();
    if let Some(form_uuids) = owned_form_uuid_values_in_text_order(text) {
        for uuid in form_uuids {
            let Some(form_ref) = form_refs.get(&uuid) else {
                continue;
            };
            if form_ref.kind != "Form"
                || !is_owned_metadata_child_path(
                    &form_ref.relative_path,
                    owner_folder,
                    owner_name,
                    "Forms",
                )
            {
                continue;
            }
            let Some(name) = source_path_file_stem(&form_ref.relative_path) else {
                continue;
            };
            if seen.insert(name.clone()) {
                names.push(name);
            }
        }
    }

    let mut path_names = form_refs
        .values()
        .filter(|form_ref| {
            form_ref.kind == "Form"
                && is_owned_metadata_child_path(
                    &form_ref.relative_path,
                    owner_folder,
                    owner_name,
                    "Forms",
                )
        })
        .filter_map(|form_ref| {
            source_path_file_stem(&form_ref.relative_path)
                .map(|name| (form_ref.relative_path.clone(), name))
        })
        .collect::<Vec<_>>();
    path_names.sort_by(|(left_path, _), (right_path, _)| left_path.cmp(right_path));
    for (_, name) in path_names {
        if seen.insert(name.clone()) {
            names.push(name);
        }
    }

    names
}

fn catalog_standard_attribute_name(code: &str) -> Option<&'static str> {
    match code {
        "-3" => Some("Description"),
        "-2" => Some("Code"),
        _ => None,
    }
}

fn form_source_reference_name(form_ref: &FormSourceReference) -> Option<String> {
    let parts = form_ref
        .relative_path
        .iter()
        .filter_map(|part| part.to_str())
        .collect::<Vec<_>>();
    if parts.len() == 2 && parts.first() == Some(&"CommonForms") {
        let form_name = Path::new(parts[1]).file_stem()?.to_str()?;
        return Some(format!("CommonForm.{form_name}"));
    }
    if parts.len() == 4 && parts.get(2) == Some(&"Forms") {
        let owner_kind = metadata_kind_for_source_folder(parts[0])?;
        let owner_name = parts[1];
        let form_name = Path::new(parts[3]).file_stem()?.to_str()?;
        return Some(format!("{owner_kind}.{owner_name}.Form.{form_name}"));
    }
    None
}

fn metadata_kind_for_source_folder(folder: &str) -> Option<&'static str> {
    match folder {
        "Catalogs" => Some("Catalog"),
        "Documents" => Some("Document"),
        "DocumentJournals" => Some("DocumentJournal"),
        "Enums" => Some("Enum"),
        "Reports" => Some("Report"),
        "DataProcessors" => Some("DataProcessor"),
        "InformationRegisters" => Some("InformationRegister"),
        "AccumulationRegisters" => Some("AccumulationRegister"),
        "AccountingRegisters" => Some("AccountingRegister"),
        "CalculationRegisters" => Some("CalculationRegister"),
        "ChartsOfAccounts" => Some("ChartOfAccounts"),
        "ChartsOfCharacteristicTypes" => Some("ChartOfCharacteristicTypes"),
        "ChartsOfCalculationTypes" => Some("ChartOfCalculationTypes"),
        "BusinessProcesses" => Some("BusinessProcess"),
        "Tasks" => Some("Task"),
        "ExchangePlans" => Some("ExchangePlan"),
        _ => None,
    }
}

fn parse_1c_bool_field(value: Option<&str>) -> Option<bool> {
    parse_1c_bool_flag(value?.trim())
}

fn parse_1c_u32_field(value: Option<&str>) -> Option<u32> {
    value?.trim().parse().ok()
}

